#[derive(Clone, Debug)]
pub struct HostedServePolicy {
    pub limits: HostedHttpLimits,
    pub auth_policy: HostedAuthPolicy,
    pub network_access_policy: Option<loom_store::NetworkAccessPolicyRecord>,
}

impl HostedServePolicy {
    pub fn new(limits: HostedHttpLimits, auth_policy: HostedAuthPolicy) -> Self {
        Self {
            limits,
            auth_policy,
            network_access_policy: None,
        }
    }

    pub fn with_network_access_policy(
        mut self,
        policy: Option<loom_store::NetworkAccessPolicyRecord>,
    ) -> Self {
        self.network_access_policy = policy;
        self
    }
}

