struct HostedHttpError(Box<Response>);

type HostedHttpResult<T> = Result<T, HostedHttpError>;

const INTERNAL_PEER_CERTIFICATE_DER_HEX: &str = "x-loom-internal-peer-certificate-der-hex";

impl HostedHttpError {
    fn into_response(self) -> Response {
        *self.0
    }
}

impl From<Response> for HostedHttpError {
    fn from(response: Response) -> Self {
        Self(Box::new(response))
    }
}

impl From<HostedHttpError> for Response {
    fn from(error: HostedHttpError) -> Self {
        error.into_response()
    }
}

async fn hosted_internal_peer_certificate_layer(mut request: Request, next: Next) -> Response {
    request
        .headers_mut()
        .remove(INTERNAL_PEER_CERTIFICATE_DER_HEX);
    let peer_certificate = request.extensions().get::<HostedPeerCertificate>().cloned();
    if let Some(peer_certificate) = peer_certificate {
        let value = hex_encode(peer_certificate.leaf_der());
        if let Ok(value) = HeaderValue::from_str(&value) {
            request
                .headers_mut()
                .insert(INTERNAL_PEER_CERTIFICATE_DER_HEX, value);
        }
    }
    next.run(request).await
}

fn hex_encode(bytes: &[u8]) -> String {
    const TABLE: &[u8; 16] = b"0123456789abcdef";
    let mut out = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        out.push(TABLE[(byte >> 4) as usize] as char);
        out.push(TABLE[(byte & 0x0f) as usize] as char);
    }
    out
}

fn hex_decode(value: &str) -> Result<Vec<u8>, LoomError> {
    if !value.len().is_multiple_of(2) {
        return Err(LoomError::invalid("hex value must have an even length"));
    }
    value
        .as_bytes()
        .chunks_exact(2)
        .map(|pair| {
            let high = internal_hex_nibble(pair[0])?;
            let low = internal_hex_nibble(pair[1])?;
            Ok((high << 4) | low)
        })
        .collect()
}

fn internal_hex_nibble(byte: u8) -> Result<u8, LoomError> {
    match byte {
        b'0'..=b'9' => Ok(byte - b'0'),
        b'a'..=b'f' => Ok(byte - b'a' + 10),
        b'A'..=b'F' => Ok(byte - b'A' + 10),
        _ => Err(LoomError::invalid("hex value contains a non-hex digit")),
    }
}

pub fn cas_rest_router(kernel: HostedKernel, workspace: WorkspaceId) -> Router {
    cas_rest_router_with_limit(kernel, workspace, 16 * 1024 * 1024)
}

pub fn cas_rest_router_with_limit(
    kernel: HostedKernel,
    workspace: WorkspaceId,
    request_size_limit: usize,
) -> Router {
    cas_rest_router_with_policy(
        kernel,
        workspace,
        request_size_limit,
        HostedAuthPolicy::OwnerOrPassphrase,
    )
}

pub fn cas_rest_router_with_policy(
    kernel: HostedKernel,
    workspace: WorkspaceId,
    request_size_limit: usize,
    auth_policy: HostedAuthPolicy,
) -> Router {
    let state = CasRestState {
        kernel,
        workspace,
        auth_policy,
    };
    Router::new()
        .route("/cas", put(cas_put).get(cas_list))
        .route(
            "/cas/{digest}",
            get(cas_get).head(cas_head).delete(cas_delete),
        )
        .layer(DefaultBodyLimit::max(request_size_limit))
        .with_state(state)
        .layer(axum::middleware::from_fn(
            hosted_internal_peer_certificate_layer,
        ))
}

