pub fn admin_rest_router_with_policy(
    kernel: HostedKernel,
    request_size_limit: usize,
    auth_policy: HostedAuthPolicy,
) -> Router {
    let state = AdminRestState {
        kernel,
        auth_policy,
    };
    Router::new()
        .route("/admin/capabilities", get(admin_capabilities))
        .route("/admin/listeners", get(admin_listeners))
        .route(
            "/admin/network-access/policies",
            get(admin_network_access_policies).put(admin_network_access_policy_set),
        )
        .route(
            "/admin/network-access/policies/{name}",
            get(admin_network_access_policy).delete(admin_network_access_policy_remove),
        )
        .route("/admin/audit", get(admin_audit))
        .route("/admin/audit/export", get(admin_audit_export))
        .route(
            "/admin/audit/config",
            get(admin_audit_config).put(admin_audit_config_set),
        )
        .route("/admin/audit/prune", post(admin_audit_prune))
        .route("/admin/identity", get(admin_identity))
        .route("/admin/identity/add", post(admin_identity_add))
        .route(
            "/admin/identity/passphrase",
            post(admin_identity_passphrase),
        )
        .route(
            "/admin/identity/authority/force-detach",
            post(admin_identity_authority_force_detach),
        )
        .route(
            "/admin/identity/authority/witness",
            get(admin_identity_authority_witness),
        )
        .route(
            "/admin/identity/app-credentials/create",
            post(admin_identity_app_credential_create),
        )
        .route(
            "/admin/identity/app-credentials/revoke",
            post(admin_identity_app_credential_revoke),
        )
        .route(
            "/admin/identity/external-credentials/create",
            post(admin_identity_external_credential_create),
        )
        .route(
            "/admin/identity/external-credentials/revoke",
            post(admin_identity_external_credential_revoke),
        )
        .route(
            "/admin/identity/public-keys/add",
            post(admin_identity_public_key_add),
        )
        .route(
            "/admin/identity/public-keys/revoke",
            post(admin_identity_public_key_revoke),
        )
        .route("/admin/identity/remove", post(admin_identity_remove))
        .route(
            "/admin/identity/roles/assign",
            post(admin_identity_role_assign),
        )
        .route(
            "/admin/identity/roles/revoke",
            post(admin_identity_role_revoke),
        )
        .route("/admin/acl", get(admin_acl))
        .route("/admin/acl/grant", post(admin_acl_grant))
        .route("/admin/acl/revoke", post(admin_acl_revoke))
        .route(
            "/admin/protected-refs/{workspace}",
            get(admin_protected_ref_list),
        )
        .route("/admin/protected-refs/get", post(admin_protected_ref_get))
        .route("/admin/protected-refs/set", post(admin_protected_ref_set))
        .route(
            "/admin/protected-refs/remove",
            post(admin_protected_ref_remove),
        )
        .route("/admin/listeners/{id}/enable", put(admin_listener_enable))
        .route("/admin/listeners/{id}/disable", put(admin_listener_disable))
        .route("/admin/listeners/{id}", delete(admin_listener_remove))
        .route("/admin/web/listeners/{id}/routes", get(admin_web_routes))
        .route(
            "/admin/web/listeners/{id}/routes/{route}",
            put(admin_web_route_set).delete(admin_web_route_remove),
        )
        .layer(DefaultBodyLimit::max(request_size_limit))
        .with_state(state)
        .layer(axum::middleware::from_fn(
            hosted_internal_peer_certificate_layer,
        ))
}

