pub fn web_rest_router_for_listener_with_policy(
    kernel: HostedKernel,
    listener: WebListener,
    request_size_limit: usize,
    auth_policy: HostedAuthPolicy,
) -> Router {
    let state = WebRestState {
        kernel,
        listener: Arc::new(listener),
        auth_policy,
    };
    Router::new()
        .route("/", get(web_get_root).head(web_head_root))
        .route("/{*path}", get(web_get_path).head(web_head_path))
        .layer(DefaultBodyLimit::max(request_size_limit))
        .with_state(state)
        .layer(axum::middleware::from_fn(
            hosted_internal_peer_certificate_layer,
        ))
}

