pub fn data_jsonrpc_router_with_profile(
    kernel: HostedKernel,
    surface: impl Into<String>,
    workspace: impl Into<String>,
    collection: impl Into<String>,
    profile: Option<impl Into<String>>,
    request_size_limit: usize,
    auth_policy: HostedAuthPolicy,
) -> Router {
    let state = DataRestState {
        kernel,
        workspace: workspace.into(),
        collection: collection.into(),
        profile: profile.map(Into::into),
        auth_policy,
        result_handles: Arc::new(Mutex::new(ServedResultHandles::default())),
    };
    Router::new()
        .route("/jsonrpc", post(data_jsonrpc))
        .layer(DefaultBodyLimit::max(request_size_limit))
        .with_state((surface.into(), state))
        .layer(axum::middleware::from_fn(
            hosted_internal_peer_certificate_layer,
        ))
}

