async fn files_jsonrpc(
    State(state): State<FilesRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let request = match serde_json::from_slice::<Value>(&body) {
        Ok(value) => value,
        Err(err) => {
            return json_response(
                StatusCode::BAD_REQUEST,
                &jsonrpc_protocol_error(Value::Null, -32700, &format!("parse error: {err}")),
            );
        }
    };
    let id = request.get("id").cloned().unwrap_or(Value::Null);
    let Some(method) = request.get("method").and_then(Value::as_str) else {
        return json_response(
            StatusCode::BAD_REQUEST,
            &jsonrpc_protocol_error(id, -32600, "missing JSON-RPC method"),
        );
    };
    let params = request.get("params").unwrap_or(&Value::Null);
    let result = match files_jsonrpc_result(method, params, &state, &auth) {
        Ok(result) => jsonrpc_success(id, result),
        Err(FilesJsonRpcFailure::Protocol(message)) => jsonrpc_protocol_error(id, -32602, &message),
        Err(FilesJsonRpcFailure::MethodNotFound) => {
            jsonrpc_protocol_error(id, -32601, "method not found")
        }
        Err(FilesJsonRpcFailure::Hosted(err)) => jsonrpc_hosted_error(id, JsonRpcError::from(err)),
        Err(FilesJsonRpcFailure::JsonRpc(err)) => jsonrpc_hosted_error(id, err),
    };
    json_response(StatusCode::OK, &result)
}

enum FilesJsonRpcFailure {
    Protocol(String),
    MethodNotFound,
    Hosted(HostedError),
    JsonRpc(JsonRpcError),
}

fn files_jsonrpc_result(
    method: &str,
    params: &Value,
    state: &FilesRestState,
    auth: &HostedAuth,
) -> Result<Value, FilesJsonRpcFailure> {
    match method {
        "fs.read_file" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let out = state
                .kernel
                .jsonrpc()
                .fs_read_file(auth, state.workspace, &path)
                .map_err(FilesJsonRpcFailure::JsonRpc)?;
            Ok(json!({ "bytes_hex": hex_bytes(&out.result) }))
        }
        "fs.write_file" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let bytes = required_files_jsonrpc_hex(params, "bytes_hex")?;
            state
                .kernel
                .jsonrpc()
                .fs_write_file(auth, state.workspace, &path, &bytes)
                .map_err(FilesJsonRpcFailure::JsonRpc)?;
            Ok(json!({ "ok": true }))
        }
        "fs.stat" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let out = state
                .kernel
                .rest()
                .head_tree(auth, state.workspace, &path)
                .map_err(|err| FilesJsonRpcFailure::Hosted(err.error))?;
            Ok(tree_metadata_json(out.body))
        }
        "fs.list_directory" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let out = state
                .kernel
                .rest()
                .list_tree(auth, state.workspace, &path)
                .map_err(|err| FilesJsonRpcFailure::Hosted(err.error))?;
            Ok(tree_entries_json(out.body))
        }
        "fs.create_directory" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let recursive = optional_files_jsonrpc_bool(params, "recursive")?.unwrap_or(false);
            state
                .kernel
                .rest()
                .create_directory(auth, state.workspace, &path, recursive)
                .map_err(|err| FilesJsonRpcFailure::Hosted(err.error))?;
            Ok(json!({ "ok": true }))
        }
        "fs.delete" => {
            let path = required_files_jsonrpc_string(params, "path")?;
            let recursive = optional_files_jsonrpc_bool(params, "recursive")?.unwrap_or(false);
            state
                .kernel
                .rest()
                .delete_tree(auth, state.workspace, &path, recursive)
                .map_err(|err| FilesJsonRpcFailure::Hosted(err.error))?;
            Ok(json!({ "ok": true }))
        }
        _ => Err(FilesJsonRpcFailure::MethodNotFound),
    }
}

async fn vcs_commit(
    State(state): State<VcsRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let message = match required_str(&value, "message") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let author = match optional_str_ref(&value, "author") {
        Ok(value) => value.unwrap_or("loom-hosted"),
        Err(response) => return response.into_response(),
    };
    let staged = match optional_bool(&value, "staged") {
        Ok(value) => value.unwrap_or(false),
        Err(response) => return response.into_response(),
    };
    match state.kernel.write(&auth, |loom| {
        if staged {
            loom.commit_staged(state.workspace, author, message, hosted_now_ms())
        } else {
            loom.commit(state.workspace, author, message, hosted_now_ms())
        }
    }) {
        Ok(commit) => json_response(
            StatusCode::CREATED,
            &json!({ "commit": commit.to_string() }).to_string(),
        ),
        Err(err) => loom_error_response(
            rest_status(err.code)
                .try_into()
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            err,
        ),
    }
}

async fn vcs_log(
    State(state): State<VcsRestState>,
    headers: HeaderMap,
    Query(query): Query<HashMap<String, String>>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let requested_ref = query.get("ref").filter(|value| !value.is_empty()).cloned();
    let limit = match query.get("limit") {
        Some(value) => match value.parse::<usize>() {
            Ok(value) => Some(value),
            Err(_) => {
                return error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "limit must be an unsigned integer",
                );
            }
        },
        None => None,
    };
    match state.kernel.read(&auth, |loom| {
        let branch = match requested_ref.as_deref() {
            Some(value) => value.to_string(),
            None => loom.registry().head_branch(state.workspace)?,
        };
        let mut commits = loom.log(state.workspace, &branch)?;
        if let Some(limit) = limit {
            commits.truncate(limit);
        }
        Ok(commits)
    }) {
        Ok(commits) => json_response(
            StatusCode::OK,
            &json!({ "commits": commits.into_iter().map(|commit| commit.to_string()).collect::<Vec<_>>() }).to_string(),
        ),
        Err(err) => loom_error_response(rest_status(err.code).try_into().unwrap_or(StatusCode::INTERNAL_SERVER_ERROR), err),
    }
}

