async fn vcs_checkout(
    State(state): State<VcsRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let target = match required_str(&value, "target") {
        Ok(value) => value.to_string(),
        Err(response) => return response.into_response(),
    };
    match state.kernel.write(&auth, |loom| {
        if loom
            .registry()
            .branch_tip(state.workspace, &target)?
            .is_some()
        {
            loom.checkout_branch(state.workspace, &target)
        } else {
            let commit = loom.resolve_rev(state.workspace, &target)?;
            loom.checkout_commit(state.workspace, commit)
        }
    }) {
        Ok(()) => response(StatusCode::NO_CONTENT, "application/json", Body::empty()),
        Err(err) => loom_error_response(
            rest_status(err.code)
                .try_into()
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            err,
        ),
    }
}

async fn vcs_diff(State(state): State<VcsRestState>, headers: HeaderMap, body: Bytes) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let from = match required_str(&value, "from") {
        Ok(value) => value.to_string(),
        Err(response) => return response.into_response(),
    };
    let to = match required_str(&value, "to") {
        Ok(value) => value.to_string(),
        Err(response) => return response.into_response(),
    };
    let format = match optional_str_ref(&value, "format") {
        Ok(value) => value.unwrap_or("hex"),
        Err(response) => return response.into_response(),
    };
    match state.kernel.read(&auth, |loom| {
        let from = loom.resolve_rev(state.workspace, &from)?;
        let to = loom.resolve_rev(state.workspace, &to)?;
        loom.diff_commits(state.workspace, from, to)
    }) {
        Ok(bytes) if format == "cbor" => {
            response(StatusCode::OK, "application/cbor", Body::from(bytes))
        }
        Ok(bytes) if format == "hex" => json_response(
            StatusCode::OK,
            &json!({ "diff_cbor_hex": hex_bytes(&bytes) }).to_string(),
        ),
        Ok(_) => error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "format must be hex or cbor",
        ),
        Err(err) => loom_error_response(
            rest_status(err.code)
                .try_into()
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            err,
        ),
    }
}

async fn vcs_merge(State(state): State<VcsRestState>, headers: HeaderMap, body: Bytes) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let source = match required_str(&value, "source") {
        Ok(value) => value.to_string(),
        Err(response) => return response.into_response(),
    };
    let author = match optional_str_ref(&value, "author") {
        Ok(value) => value.unwrap_or("loom-hosted").to_string(),
        Err(response) => return response.into_response(),
    };
    let cells = match optional_bool(&value, "cells") {
        Ok(value) => value.unwrap_or(false),
        Err(response) => return response.into_response(),
    };
    match state.kernel.write(&auth, |loom| {
        if cells {
            loom.merge_cell_level(state.workspace, &source, &author, hosted_now_ms())
        } else {
            loom.merge(state.workspace, &source, &author, hosted_now_ms())
        }
    }) {
        Ok(outcome) => json_response(StatusCode::OK, &merge_outcome_json(outcome).to_string()),
        Err(err) => loom_error_response(
            rest_status(err.code)
                .try_into()
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            err,
        ),
    }
}

