async fn vcs_unstage(
    State(state): State<VcsRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let paths = match string_array_field(&value, "paths") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let refs = paths.iter().map(String::as_str).collect::<Vec<_>>();
    match state
        .kernel
        .write(&auth, |loom| loom.unstage(state.workspace, &refs))
    {
        Ok(()) => response(StatusCode::NO_CONTENT, "application/json", Body::empty()),
        Err(err) => loom_error_response(
            rest_status(err.code)
                .try_into()
                .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            err,
        ),
    }
}

async fn vcs_jsonrpc(
    State(state): State<VcsRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let request = match serde_json::from_slice::<Value>(&body) {
        Ok(value) => value,
        Err(err) => {
            return json_response(
                StatusCode::BAD_REQUEST,
                &jsonrpc_protocol_error(Value::Null, -32700, &format!("parse error: {err}")),
            );
        }
    };
    let id = request.get("id").cloned().unwrap_or(Value::Null);
    let Some(method) = request.get("method").and_then(Value::as_str) else {
        return json_response(
            StatusCode::BAD_REQUEST,
            &jsonrpc_protocol_error(id, -32600, "missing JSON-RPC method"),
        );
    };
    let params = request.get("params").unwrap_or(&Value::Null);
    let result = match vcs_jsonrpc_result(method, params, &state, &auth) {
        Ok(result) => jsonrpc_success(id, result),
        Err(VcsJsonRpcFailure::Protocol(message)) => jsonrpc_protocol_error(id, -32602, &message),
        Err(VcsJsonRpcFailure::MethodNotFound) => {
            jsonrpc_protocol_error(id, -32601, "method not found")
        }
        Err(VcsJsonRpcFailure::Hosted(err)) => jsonrpc_hosted_error(id, JsonRpcError::from(err)),
    };
    json_response(StatusCode::OK, &result)
}

enum VcsJsonRpcFailure {
    Protocol(String),
    MethodNotFound,
    Hosted(HostedError),
}

fn vcs_jsonrpc_result(
    method: &str,
    params: &Value,
    state: &VcsRestState,
    auth: &HostedAuth,
) -> Result<Value, VcsJsonRpcFailure> {
    match method {
        "vcs.commit" => {
            let message = required_vcs_jsonrpc_string(params, "message")?;
            let author = optional_vcs_jsonrpc_string(params, "author")?
                .unwrap_or_else(|| "loom-hosted".to_string());
            let staged = optional_vcs_jsonrpc_bool(params, "staged")?.unwrap_or(false);
            let commit = state
                .kernel
                .write(auth, |loom| {
                    if staged {
                        loom.commit_staged(state.workspace, &author, &message, hosted_now_ms())
                    } else {
                        loom.commit(state.workspace, &author, &message, hosted_now_ms())
                    }
                })
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "commit": commit.to_string() }))
        }
        "vcs.log" => {
            let requested_ref = optional_vcs_jsonrpc_string(params, "ref")?;
            let commits = state
                .kernel
                .read(auth, |loom| {
                    let branch = match requested_ref.as_deref() {
                        Some(value) => value.to_string(),
                        None => loom.registry().head_branch(state.workspace)?,
                    };
                    loom.log(state.workspace, &branch)
                })
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(
                json!({ "commits": commits.into_iter().map(|commit| commit.to_string()).collect::<Vec<_>>() }),
            )
        }
        "vcs.branch" => {
            let name = required_vcs_jsonrpc_string(params, "name")?;
            state
                .kernel
                .write(auth, |loom| loom.branch(state.workspace, &name))
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "ok": true }))
        }
        "vcs.checkout" => {
            let target = required_vcs_jsonrpc_string(params, "target")?;
            state
                .kernel
                .write(auth, |loom| {
                    if loom
                        .registry()
                        .branch_tip(state.workspace, &target)?
                        .is_some()
                    {
                        loom.checkout_branch(state.workspace, &target)
                    } else {
                        let commit = loom.resolve_rev(state.workspace, &target)?;
                        loom.checkout_commit(state.workspace, commit)
                    }
                })
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "ok": true }))
        }
        "vcs.status" => {
            let status = state
                .kernel
                .read(auth, |loom| loom.status(state.workspace))
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(status_json(status))
        }
        "vcs.stage" => {
            let paths = string_array_jsonrpc(params, "paths")?;
            let refs = paths.iter().map(String::as_str).collect::<Vec<_>>();
            state
                .kernel
                .write(auth, |loom| loom.stage(state.workspace, &refs))
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "ok": true }))
        }
        "vcs.stage_all" => {
            state
                .kernel
                .write(auth, |loom| loom.stage_all(state.workspace))
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "ok": true }))
        }
        "vcs.unstage" => {
            let paths = string_array_jsonrpc(params, "paths")?;
            let refs = paths.iter().map(String::as_str).collect::<Vec<_>>();
            state
                .kernel
                .write(auth, |loom| loom.unstage(state.workspace, &refs))
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "ok": true }))
        }
        "vcs.merge" => {
            let source = required_vcs_jsonrpc_string(params, "source")?;
            let author = optional_vcs_jsonrpc_string(params, "author")?
                .unwrap_or_else(|| "loom-hosted".to_string());
            let cells = optional_vcs_jsonrpc_bool(params, "cells")?.unwrap_or(false);
            let outcome = state
                .kernel
                .write(auth, |loom| {
                    if cells {
                        loom.merge_cell_level(state.workspace, &source, &author, hosted_now_ms())
                    } else {
                        loom.merge(state.workspace, &source, &author, hosted_now_ms())
                    }
                })
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(merge_outcome_json(outcome))
        }
        "vcs.diff" => {
            let from = required_vcs_jsonrpc_string(params, "from")?;
            let to = required_vcs_jsonrpc_string(params, "to")?;
            let bytes = state
                .kernel
                .read(auth, |loom| {
                    let from = loom.resolve_rev(state.workspace, &from)?;
                    let to = loom.resolve_rev(state.workspace, &to)?;
                    loom.diff_commits(state.workspace, from, to)
                })
                .map_err(|err| VcsJsonRpcFailure::Hosted(HostedError::from_error(err)))?;
            Ok(json!({ "diff_cbor_hex": hex_bytes(&bytes) }))
        }
        _ => Err(VcsJsonRpcFailure::MethodNotFound),
    }
}

