#[derive(Clone)]
struct WatchStreamState {
    kernel: HostedKernel,
    auth: HostedAuth,
    workspace: WorkspaceId,
    cursor: String,
    max: u32,
    interval: Duration,
    debounce: Duration,
    remaining: Option<usize>,
}

async fn watch_stream(
    State(state): State<WatchRestState>,
    headers: HeaderMap,
    Query(query): Query<HashMap<String, String>>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let Some(cursor) = query.get("cursor").cloned() else {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "missing cursor",
        );
    };
    let max = match watch_poll_max(query.get("max").map(String::as_str)) {
        Ok(max) => max,
        Err(response) => return response.into_response(),
    };
    let interval = match optional_duration_ms(&query, "interval_ms", 250, 10, 60_000) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let debounce = match optional_duration_ms(&query, "debounce_ms", 0, 0, 60_000) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let remaining = match optional_usize_query(&query, "limit") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let stream_state = WatchStreamState {
        kernel: state.kernel,
        auth,
        workspace: state.workspace,
        cursor,
        max,
        interval,
        debounce,
        remaining,
    };
    let body = Body::from_stream(stream::unfold(stream_state, watch_stream_next));
    response(StatusCode::OK, "text/event-stream", body)
}

async fn watch_stream_next(
    mut state: WatchStreamState,
) -> Option<(Result<Bytes, Infallible>, WatchStreamState)> {
    loop {
        if state.remaining == Some(0) {
            return None;
        }
        if !state.debounce.is_zero() {
            tokio::time::sleep(state.debounce).await;
        }
        match state
            .kernel
            .rest()
            .watch_poll(&state.auth, state.workspace, &state.cursor, state.max)
        {
            Ok(out) if out.body.events.is_empty() => {
                tokio::time::sleep(state.interval).await;
            }
            Ok(out) => {
                let frame = crate::watch::watch_stream_frame(out.body);
                state.cursor = frame.next.clone();
                if let Some(remaining) = state.remaining.as_mut() {
                    *remaining = remaining.saturating_sub(1);
                }
                let bytes = sse_json_event("data-change", &frame.next, &frame);
                return Some((Ok(Bytes::from(bytes)), state));
            }
            Err(err) => {
                state.remaining = Some(0);
                let error = json!({
                    "code": err.error.code_number,
                    "code_name": err.error.code_name,
                    "message": err.error.message,
                });
                let bytes = sse_json_event("error", "", &error);
                return Some((Ok(Bytes::from(bytes)), state));
            }
        }
    }
}

