enum WatchJsonRpcFailure {
    Protocol(String),
    MethodNotFound,
    JsonRpc(JsonRpcError),
}

fn watch_jsonrpc_result(
    method: &str,
    params: &Value,
    state: &WatchRestState,
    auth: &HostedAuth,
) -> Result<Value, WatchJsonRpcFailure> {
    match method {
        "watch.subscribe" => {
            let input = serde_json::from_value::<HostedWatchSubscribeInput>(params.clone())
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))?;
            let out = state
                .kernel
                .jsonrpc()
                .watch_subscribe(auth, state.workspace, &input)
                .map_err(WatchJsonRpcFailure::JsonRpc)?;
            serde_json::to_value(out.result)
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))
        }
        "watch.poll" => {
            let cursor = required_watch_jsonrpc_string(params, "cursor")?;
            let max = optional_watch_jsonrpc_u32(params, "max")?.unwrap_or(100);
            let out = state
                .kernel
                .jsonrpc()
                .watch_poll(auth, state.workspace, &cursor, max)
                .map_err(WatchJsonRpcFailure::JsonRpc)?;
            serde_json::to_value(out.result)
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))
        }
        "watch.stream" => {
            let cursor = required_watch_jsonrpc_string(params, "cursor")?;
            let max = optional_watch_jsonrpc_u32(params, "max")?.unwrap_or(100);
            let interval_ms = optional_watch_jsonrpc_u64(params, "interval_ms")?.unwrap_or(250);
            let debounce_ms = optional_watch_jsonrpc_u64(params, "debounce_ms")?.unwrap_or(0);
            let limit = optional_watch_jsonrpc_u64(params, "limit")?;
            let out = state
                .kernel
                .jsonrpc()
                .watch_stream(
                    auth,
                    crate::jsonrpc::JsonRpcWatchStreamInput {
                        workspace: state.workspace,
                        cursor: &cursor,
                        max,
                        interval_ms,
                        debounce_ms,
                        limit,
                    },
                )
                .map_err(WatchJsonRpcFailure::JsonRpc)?;
            serde_json::to_value(out.result)
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))
        }
        "watch.materialize" => {
            let input = serde_json::from_value::<HostedWatchMaterializeInput>(params.clone())
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))?;
            let out = state
                .kernel
                .jsonrpc()
                .watch_materialize(auth, state.workspace, &input)
                .map_err(WatchJsonRpcFailure::JsonRpc)?;
            serde_json::to_value(out.result)
                .map_err(|err| WatchJsonRpcFailure::Protocol(err.to_string()))
        }
        _ => Err(WatchJsonRpcFailure::MethodNotFound),
    }
}

