fn drive_rest_json<T: serde::Serialize>(result: crate::rest::RestResult<T>) -> Response {
    match result {
        Ok(out) => json_body_response(
            StatusCode::from_u16(out.status).unwrap_or(StatusCode::OK),
            &out.body,
        ),
        Err(err) => rest_failure_response(err),
    }
}

fn drive_os_projection_json(projection: &HostedDriveOsFileProjection) -> Value {
    json!({
        "workspace_id": projection.workspace_id,
        "file_id": projection.file_id,
        "profile_root": projection.profile_root,
        "state": projection.state,
        "size": projection.size,
        "content_digest": projection.content_digest,
        "uri": projection.uri,
        "bytes_hex": hex_bytes(&projection.bytes)
    })
}

fn drive_os_materialized_files(
    value: &Value,
) -> HostedHttpResult<Vec<HostedDriveOsMaterializedFile>> {
    let items = value
        .get("materialized")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "materialized must be an array",
            )
        })?;
    items
        .iter()
        .map(|item| {
            let file_id = required_str(item, "file_id")?.to_string();
            let hydrated = bool_field(item, "hydrated")?;
            let pinned = bool_field(item, "pinned")?;
            let safely_replicated = bool_field(item, "safely_replicated")?;
            Ok(HostedDriveOsMaterializedFile {
                file_id,
                hydrated,
                pinned,
                safely_replicated,
            })
        })
        .collect()
}

fn drive_resolution(
    value: Result<&str, HostedHttpError>,
) -> HostedHttpResult<HostedDriveConflictResolution> {
    match value? {
        "keep_current" | "keep-current" => Ok(HostedDriveConflictResolution::KeepCurrent),
        "keep_conflict" | "keep-conflict" => Ok(HostedDriveConflictResolution::KeepConflict),
        "keep_both" | "keep-both" => Ok(HostedDriveConflictResolution::KeepBoth),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "resolution must be keep_current, keep_conflict, or keep_both",
        )
        .into()),
    }
}

