async fn chat_reaction(
    state: DataRestState,
    headers: HeaderMap,
    body: Bytes,
    add: bool,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let value = match parse_json_body(&body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let (workspace, channel_id) = match chat_target(&state, &auth) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let message_id = match required_str(&value, "message_id") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let kind = match required_str(&value, "kind") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let result = if add {
        state.kernel.rest().chat_add_reaction(
            &auth,
            workspace,
            &state.collection,
            channel_id,
            message_id,
            kind,
        )
    } else {
        state.kernel.rest().chat_remove_reaction(
            &auth,
            workspace,
            &state.collection,
            channel_id,
            message_id,
            kind,
        )
    };
    chat_rest_json(result)
}

