fn chat_target<'a>(
    state: &'a DataRestState,
    auth: &HostedAuth,
) -> HostedHttpResult<(WorkspaceId, &'a str)> {
    let workspace = hosted_workspace_id(&state.kernel, auth, &state.workspace)?;
    let Some(channel_id) = state.profile.as_deref() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "chat listener requires a channel selector",
        )
        .into());
    };
    Ok((workspace, channel_id))
}

fn chat_rest_json<T: serde::Serialize>(result: crate::rest::RestResult<T>) -> Response {
    match result {
        Ok(out) => json_body_response(
            StatusCode::from_u16(out.status).unwrap_or(StatusCode::OK),
            &out.body,
        ),
        Err(err) => rest_failure_response(err),
    }
}

