async fn meetings_propose_vocabulary(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let workspace = match hosted_workspace_id(&state.kernel, &auth, &state.workspace) {
        Ok(workspace) => workspace,
        Err(response) => return response.into_response(),
    };
    let term_id = match required_str(&value, "term_id") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let kind = match required_str(&value, "kind") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let label = match required_str(&value, "label") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let evidence_annotation_ids = match string_array_field(&value, "evidence_annotation_ids") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let aliases = if value.get("aliases").is_some() {
        match string_array_field(&value, "aliases") {
            Ok(value) => value,
            Err(response) => return response.into_response(),
        }
    } else {
        Vec::new()
    };
    let input = loom_substrate::meetings::VocabularyTermInput {
        term_id,
        kind,
        label,
        evidence_annotation_ids,
        created_at_ms: crate::chat::now_ms(),
    };
    drive_rest_json(state.kernel.rest().meetings_propose_vocabulary(
        &auth,
        workspace,
        &state.collection,
        input,
        aliases,
    ))
}

