async fn influx_write(
    State(state): State<InfluxHttpState>,
    headers: HeaderMap,
    Query(query): Query<HashMap<String, String>>,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let bucket = match query.get("bucket").or_else(|| query.get("db")) {
        Some(bucket) if !bucket.is_empty() => bucket,
        _ => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "missing Influx bucket",
            )
            .into_response();
        }
    };
    let precision = query.get("precision").map(String::as_str).unwrap_or("ns");
    let body = match std::str::from_utf8(&body) {
        Ok(body) => body,
        Err(_) => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "Influx line protocol must be UTF-8",
            )
            .into_response();
        }
    };
    let points = match parse_influx_line_protocol(body, precision) {
        Ok(points) => points,
        Err(response) => return response.into_response(),
    };
    match state.kernel.data().timeseries_put_structured_batch(
        &auth,
        &state.workspace,
        bucket,
        points,
    ) {
        Ok(_) => (StatusCode::NO_CONTENT, "").into_response(),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

async fn prometheus_remote_write(
    State(state): State<PrometheusHttpState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let decoded = match snap::raw::Decoder::new().decompress_vec(&body) {
        Ok(decoded) => decoded,
        Err(_) => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "invalid Prometheus remote write Snappy payload",
            )
            .into_response();
        }
    };
    let request = match prometheus_proto::WriteRequest::decode(decoded.as_slice()) {
        Ok(request) => request,
        Err(_) => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "invalid Prometheus remote write protobuf payload",
            )
            .into_response();
        }
    };
    let points = match prometheus_points_from_write_request(request) {
        Ok(points) => points,
        Err(response) => return response.into_response(),
    };
    match state.kernel.data().timeseries_put_structured_batch(
        &auth,
        &state.workspace,
        PROMETHEUS_COLLECTION,
        points,
    ) {
        Ok(_) => (StatusCode::NO_CONTENT, "").into_response(),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

