async fn prometheus_query_range(
    State(state): State<PrometheusHttpState>,
    headers: HeaderMap,
    Query(query): Query<HashMap<String, String>>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let selector = match prometheus_selector_from_query(&query) {
        Ok(selector) => selector,
        Err(response) => return response.into_response(),
    };
    let start_ns = match query.get("start") {
        Some(value) => match prometheus_seconds_to_ns(value) {
            Ok(value) => value,
            Err(response) => return response.into_response(),
        },
        None => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "missing Prometheus query_range start",
            )
            .into_response();
        }
    };
    let end_ns = match query.get("end") {
        Some(value) => match prometheus_seconds_to_ns(value) {
            Ok(value) => value,
            Err(response) => return response.into_response(),
        },
        None => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "missing Prometheus query_range end",
            )
            .into_response();
        }
    };
    let points = match state.kernel.data().timeseries_range_structured(
        &auth,
        &state.workspace,
        PROMETHEUS_COLLECTION,
        start_ns,
        end_ns.saturating_add(1),
    ) {
        Ok(points) => points,
        Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
    };
    let result = prometheus_matrix_json(points, selector);
    json_response(
        StatusCode::OK,
        &json!({ "status": "success", "data": { "resultType": "matrix", "result": result } })
            .to_string(),
    )
}

