async fn grafana_search(
    State(state): State<GrafanaHttpState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let value = match parse_json_body(&body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let from_ns = value
        .get("from_ns")
        .and_then(Value::as_i64)
        .unwrap_or(i64::MIN);
    let to_ns = value
        .get("to_ns")
        .and_then(Value::as_i64)
        .unwrap_or(i64::MAX);
    let points = match state.kernel.data().timeseries_range_structured(
        &auth,
        &state.workspace,
        &state.collection,
        from_ns,
        to_ns,
    ) {
        Ok(points) => points,
        Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
    };
    let mut targets = points
        .into_iter()
        .map(|point| point.measurement)
        .collect::<Vec<_>>();
    targets.sort();
    targets.dedup();
    json_response(StatusCode::OK, &json!(targets).to_string())
}

async fn grafana_query(
    State(state): State<GrafanaHttpState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let value = match parse_json_body(&body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let from_ns = value
        .get("from_ns")
        .and_then(Value::as_i64)
        .unwrap_or(i64::MIN);
    let to_ns = value
        .get("to_ns")
        .and_then(Value::as_i64)
        .unwrap_or(i64::MAX);
    let points = match state.kernel.data().timeseries_range_structured(
        &auth,
        &state.workspace,
        &state.collection,
        from_ns,
        to_ns,
    ) {
        Ok(points) => points,
        Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
    };
    let targets = value
        .get("targets")
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let mut response = Vec::new();
    for target in targets {
        let selector_text = target
            .get("target")
            .and_then(Value::as_str)
            .unwrap_or_default();
        let selector = match parse_prometheus_selector(selector_text) {
            Ok(selector) => selector,
            Err(response) => return response.into_response(),
        };
        let datapoints = points
            .iter()
            .filter(|point| prometheus_point_matches(point, &selector))
            .filter_map(|point| {
                let value = match point.fields.get("value")? {
                    TimeSeriesValue::Int(value) => *value as f64,
                    TimeSeriesValue::Float(value) if value.is_finite() => *value,
                    _ => return None,
                };
                Some(json!([value, point.timestamp_ns / 1_000_000]))
            })
            .collect::<Vec<_>>();
        response.push(json!({
            "target": selector_text,
            "datapoints": datapoints,
        }));
    }
    json_response(StatusCode::OK, &json!(response).to_string())
}

