async fn qdrant_collection_info(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(collection): Path<String>,
) -> Response {
    if let Err(response) = qdrant_collection_matches(&state, &collection) {
        return response.into_response();
    }
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let mapping = match crate::vector_compat::qdrant_mapping(&collection, None) {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    match state
        .kernel
        .data()
        .vector_info(&auth, &state.workspace, &mapping.vector_set)
    {
        Ok(info) => qdrant_response(json!({
            "status": "green",
            "vectors_count": info.count,
            "points_count": info.count,
            "config": {
                "params": {
                    "vectors": {
                        "size": info.dim,
                        "distance": qdrant_metric_json(info.metric)
                    }
                }
            }
        })),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

async fn qdrant_collection_create(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(collection): Path<String>,
    body: Bytes,
) -> Response {
    if let Err(response) = qdrant_collection_matches(&state, &collection) {
        return response.into_response();
    }
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let specs = match qdrant_vector_specs(&value) {
        Ok(specs) => specs,
        Err(response) => return response.into_response(),
    };
    for (name, dim, metric) in specs {
        let mapping = match crate::vector_compat::qdrant_mapping(&collection, name.as_deref()) {
            Ok(mapping) => mapping,
            Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
        };
        if let Err(err) = state.kernel.data().vector_create(
            &auth,
            &state.workspace,
            &mapping.vector_set,
            dim,
            metric,
        ) {
            return hosted_error_response(StatusCode::FORBIDDEN, err);
        }
    }
    qdrant_response(json!({ "operation_id": 0, "status": "completed" }))
}

async fn qdrant_points_upsert(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(collection): Path<String>,
    body: Bytes,
) -> Response {
    if let Err(response) = qdrant_collection_matches(&state, &collection) {
        return response.into_response();
    }
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let Some(points) = value.get("points").and_then(Value::as_array) else {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "points must be an array",
        );
    };
    for point in points {
        let id = match qdrant_point_id(point.get("id")) {
            Ok(id) => id,
            Err(response) => return response.into_response(),
        };
        let payload = match qdrant_payload(point.get("payload")) {
            Ok(payload) => payload,
            Err(response) => return response.into_response(),
        };
        let vectors = match qdrant_point_vectors(point) {
            Ok(vectors) => vectors,
            Err(response) => return response.into_response(),
        };
        for (name, vector) in vectors {
            let mapping = match crate::vector_compat::qdrant_mapping(&collection, name.as_deref()) {
                Ok(mapping) => mapping,
                Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
            };
            if let Err(err) = state.kernel.data().vector_upsert(
                &auth,
                &state.workspace,
                &mapping.vector_set,
                &id,
                vector,
                payload.clone(),
            ) {
                return hosted_error_response(StatusCode::FORBIDDEN, err);
            }
        }
    }
    qdrant_response(json!({ "operation_id": 0, "status": "completed" }))
}

