async fn qdrant_search_like(
    state: DataRestState,
    headers: HeaderMap,
    collection: String,
    body: Bytes,
    query_field: &str,
) -> Response {
    if let Err(response) = qdrant_collection_matches(&state, &collection) {
        return response.into_response();
    }
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let (name, query) = match qdrant_query_vector(&value, query_field) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let limit = match qdrant_limit(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let filter = match qdrant_filter(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let mapping = match crate::vector_compat::qdrant_mapping(&collection, name.as_deref()) {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    let data = state.kernel.data();
    match data.vector_search_filtered(
        &auth,
        &state.workspace,
        &mapping.vector_set,
        &query,
        limit,
        &filter,
    ) {
        Ok(hits) => {
            let with_payload = qdrant_with_payload(&value);
            let with_vector = qdrant_with_vector(&value);
            let mut points = Vec::with_capacity(hits.len());
            for hit in hits {
                let entry =
                    match data.vector_get(&auth, &state.workspace, &mapping.vector_set, &hit.id) {
                        Ok(entry) => entry,
                        Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
                    };
                if let Some(entry) = entry {
                    points.push(qdrant_point_json(
                        hit.id,
                        entry,
                        with_payload,
                        with_vector,
                        Some(hit.score),
                    ));
                }
            }
            qdrant_response(Value::Array(points))
        }
        Err(err) if err.code == Code::NotFound => json_response(
            StatusCode::OK,
            &json!({
                "dimension": 0,
                "index_fullness": 0.0,
                "metric": "cosine",
                "workspaces": {},
                "total_vector_count": 0
            })
            .to_string(),
        ),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

async fn qdrant_points_scroll(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(collection): Path<String>,
    body: Bytes,
) -> Response {
    if let Err(response) = qdrant_collection_matches(&state, &collection) {
        return response.into_response();
    }
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let limit = match qdrant_limit(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let offset = match qdrant_optional_id(value.get("offset")) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let filter = match qdrant_filter(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let mapping = match crate::vector_compat::qdrant_mapping(&collection, None) {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    match state.kernel.data().vector_scroll(
        &auth,
        &state.workspace,
        &mapping.vector_set,
        offset.as_deref(),
        limit,
        &filter,
    ) {
        Ok(points) => {
            let with_payload = qdrant_with_payload_default_true(&value);
            let with_vector = qdrant_with_vector(&value);
            let next_page_offset = if points.len() == limit {
                points.last().map(|(id, _)| id.clone())
            } else {
                None
            };
            qdrant_response(json!({
                "points": points
                    .into_iter()
                    .map(|(id, entry)| qdrant_point_json(id, entry, with_payload, with_vector, None))
                    .collect::<Vec<_>>(),
                "next_page_offset": next_page_offset
            }))
        }
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

