async fn pinecone_describe_index_stats(
    State(state): State<DataRestState>,
    headers: HeaderMap,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    match state.kernel.data().vector_pinecone_workspace_stats(
        &auth,
        &state.workspace,
        &state.collection,
    ) {
        Ok(stats) => {
            let mut workspaces = serde_json::Map::new();
            let mut dimension = 0usize;
            let mut metric = "cosine";
            let mut total = 0usize;
            for stat in stats {
                if dimension == 0 {
                    dimension = stat.dim;
                    metric = pinecone_metric_json(stat.metric);
                }
                total += stat.count;
                workspaces.insert(stat.workspace, json!({ "vector_count": stat.count }));
            }
            json_response(
                StatusCode::OK,
                &json!({
                    "dimension": dimension,
                    "index_fullness": 0.0,
                    "metric": metric,
                    "workspaces": workspaces,
                    "total_vector_count": total
                })
                .to_string(),
            )
        }
        Err(err) if err.code == Code::NotFound => json_response(
            StatusCode::OK,
            &json!({
                "dimension": 0,
                "index_fullness": 0.0,
                "metric": "cosine",
                "workspaces": {},
                "total_vector_count": 0
            })
            .to_string(),
        ),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

async fn pinecone_vectors_upsert(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let workspace = pinecone_workspace(&value);
    let Some(vectors) = value.get("vectors").and_then(Value::as_array) else {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vectors must be an array",
        );
    };
    let mapping = match crate::vector_compat::pinecone_mapping(&state.collection, Some(&workspace))
    {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    let mut upserted_count = 0usize;
    for item in vectors {
        let id = match pinecone_id(item) {
            Ok(id) => id,
            Err(response) => return response.into_response(),
        };
        if let Err(response) = pinecone_reject_integrated_embedding(item) {
            return response.into_response();
        }
        let values = match pinecone_values(item, "values") {
            Ok(values) => values,
            Err(response) => return response.into_response(),
        };
        let metadata = match pinecone_metadata(item.get("metadata")) {
            Ok(metadata) => metadata,
            Err(response) => return response.into_response(),
        };
        match state.kernel.data().vector_upsert(
            &auth,
            &state.workspace,
            &mapping.vector_set,
            &id,
            values.clone(),
            metadata.clone(),
        ) {
            Ok(()) => {}
            Err(err) if err.code == Code::NotFound => {
                if let Err(err) = state.kernel.data().vector_create(
                    &auth,
                    &state.workspace,
                    &mapping.vector_set,
                    values.len(),
                    loom_core::Metric::Cosine,
                ) {
                    return hosted_error_response(StatusCode::FORBIDDEN, err);
                }
                if let Err(err) = state.kernel.data().vector_upsert(
                    &auth,
                    &state.workspace,
                    &mapping.vector_set,
                    &id,
                    values,
                    metadata,
                ) {
                    return hosted_error_response(StatusCode::FORBIDDEN, err);
                }
            }
            Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
        }
        upserted_count += 1;
    }
    json_response(
        StatusCode::OK,
        &json!({ "upsertedCount": upserted_count }).to_string(),
    )
}

async fn pinecone_vectors_fetch(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    RawQuery(query): RawQuery,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let params = parse_query_params(query.as_deref().unwrap_or(""));
    let workspace = query_param(&params, "workspace").unwrap_or(DEFAULT_WORKSPACE);
    let ids = query_values(&params, "ids")
        .into_iter()
        .flat_map(split_csv)
        .filter(|id| !id.is_empty())
        .collect::<Vec<_>>();
    if ids.is_empty() {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "ids query parameter is required",
        );
    }
    let mapping = match crate::vector_compat::pinecone_mapping(&state.collection, Some(workspace)) {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    let mut vectors = serde_json::Map::new();
    for id in ids {
        match state
            .kernel
            .data()
            .vector_get(&auth, &state.workspace, &mapping.vector_set, &id)
        {
            Ok(Some(entry)) => {
                vectors.insert(
                    id.clone(),
                    pinecone_vector_json(id, entry, true, true, None),
                );
            }
            Ok(None) => {}
            Err(err) if err.code == Code::NotFound => {}
            Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
        }
    }
    json_response(
        StatusCode::OK,
        &json!({ "workspace": workspace, "vectors": vectors }).to_string(),
    )
}

async fn pinecone_vectors_delete(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let workspace = pinecone_workspace(&value);
    let mapping = match crate::vector_compat::pinecone_mapping(&state.collection, Some(&workspace))
    {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    if value
        .get("deleteAll")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unsupported vector compatibility operation: pinecone deleteAll",
        );
    }
    let Some(ids) = value.get("ids").and_then(Value::as_array) else {
        return error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "ids must be an array",
        );
    };
    for id in ids {
        let Some(id) = id.as_str().filter(|id| !id.is_empty()) else {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "ids entries must be non-empty strings",
            );
        };
        if let Err(err) =
            state
                .kernel
                .data()
                .vector_delete(&auth, &state.workspace, &mapping.vector_set, id)
            && err.code != Code::NotFound
        {
            return hosted_error_response(StatusCode::FORBIDDEN, err);
        }
    }
    json_response(StatusCode::OK, "{}")
}

async fn pinecone_vectors_list(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    RawQuery(query): RawQuery,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let params = parse_query_params(query.as_deref().unwrap_or(""));
    let workspace = query_param(&params, "workspace").unwrap_or(DEFAULT_WORKSPACE);
    let prefix = query_param(&params, "prefix").unwrap_or("");
    let limit = match query_param(&params, "limit") {
        Some(value) => match value.parse::<usize>() {
            Ok(value) if value > 0 => value,
            _ => {
                return error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "limit must be a positive integer",
                );
            }
        },
        None => 100,
    };
    let pagination_token = query_param(&params, "paginationToken");
    let mapping = match crate::vector_compat::pinecone_mapping(&state.collection, Some(workspace)) {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    match state.kernel.data().vector_scroll(
        &auth,
        &state.workspace,
        &mapping.vector_set,
        pagination_token,
        limit,
        &loom_core::vector::MetaFilter::All,
    ) {
        Ok(points) => {
            let mut ids = Vec::new();
            let mut next = None;
            for (id, _) in points {
                if !prefix.is_empty() && !id.starts_with(prefix) {
                    continue;
                }
                next = Some(id.clone());
                ids.push(json!({ "id": id }));
                if ids.len() == limit {
                    break;
                }
            }
            let pagination = if ids.len() == limit {
                next.map(|token| json!({ "next": token }))
                    .unwrap_or(Value::Null)
            } else {
                Value::Null
            };
            json_response(
                StatusCode::OK,
                &json!({ "vectors": ids, "pagination": pagination, "workspace": workspace })
                    .to_string(),
            )
        }
        Err(err) if err.code == Code::NotFound => json_response(
            StatusCode::OK,
            &json!({ "vectors": [], "pagination": Value::Null, "workspace": workspace })
                .to_string(),
        ),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

async fn pinecone_query(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    if let Err(response) = pinecone_reject_integrated_embedding(&value) {
        return response.into_response();
    }
    let workspace = pinecone_workspace(&value);
    let query = match pinecone_query_values(&value) {
        Ok(query) => query,
        Err(response) => return response.into_response(),
    };
    let top_k = match pinecone_top_k(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let filter = match crate::vector_compat::pinecone_filter_from_json(
        value.get("filter").unwrap_or(&Value::Null),
    ) {
        Ok(filter) => filter,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    let mapping = match crate::vector_compat::pinecone_mapping(&state.collection, Some(&workspace))
    {
        Ok(mapping) => mapping,
        Err(err) => return loom_error_response(StatusCode::BAD_REQUEST, err),
    };
    let include_values = value
        .get("includeValues")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let include_metadata = value
        .get("includeMetadata")
        .and_then(Value::as_bool)
        .unwrap_or(false);
    match state.kernel.data().vector_search_filtered(
        &auth,
        &state.workspace,
        &mapping.vector_set,
        &query,
        top_k,
        &filter,
    ) {
        Ok(hits) => {
            let data = state.kernel.data();
            let mut matches = Vec::with_capacity(hits.len());
            for hit in hits {
                match data.vector_get(&auth, &state.workspace, &mapping.vector_set, &hit.id) {
                    Ok(Some(entry)) => matches.push(pinecone_vector_json(
                        hit.id,
                        entry,
                        include_values,
                        include_metadata,
                        Some(hit.score),
                    )),
                    Ok(None) => {}
                    Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
                }
            }
            json_response(
                StatusCode::OK,
                &json!({ "matches": matches, "workspace": workspace }).to_string(),
            )
        }
        Err(err) if err.code == Code::NotFound => json_response(
            StatusCode::OK,
            &json!({ "matches": [], "workspace": workspace }).to_string(),
        ),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

