async fn opensearch_aliases_update(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let actions = match opensearch_alias_actions(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let actions = actions
        .into_iter()
        .map(|action| match action {
            OpenSearchAliasAction::Add {
                index,
                alias,
                is_write_index,
            } => crate::data::HostedSearchAliasAction::Add {
                index,
                alias,
                is_write_index,
            },
            OpenSearchAliasAction::Remove { alias } => {
                crate::data::HostedSearchAliasAction::Remove { alias }
            }
        })
        .collect::<Vec<_>>();
    if let Err(err) = state
        .kernel
        .data()
        .search_alias_update(&auth, &state.workspace, actions)
    {
        return hosted_error_response(StatusCode::FORBIDDEN, err);
    }
    json_response(StatusCode::OK, &json!({ "acknowledged": true }).to_string())
}

async fn opensearch_doc_index(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path((index, id)): Path<(String, String)>,
    RawQuery(raw_query): RawQuery,
    body: Bytes,
) -> Response {
    if let Err(response) = opensearch_refresh_query(raw_query.as_deref()) {
        return response.into_response();
    }
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let target = match opensearch_write_index(&state, &auth, &index) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let doc = match opensearch_document(&value) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    match state.kernel.data().search_index(
        &auth,
        &state.workspace,
        &target,
        id.as_bytes().to_vec(),
        doc,
    ) {
        Ok(()) => json_response(
            StatusCode::CREATED,
            &json!({
                "_index": index,
                "_id": id,
                "result": "created",
                "_shards": { "total": 1, "successful": 1, "failed": 0 }
            })
            .to_string(),
        ),
        Err(err) => hosted_error_response(StatusCode::FORBIDDEN, err),
    }
}

