fn opensearch_refresh_authorized(
    state: DataRestState,
    headers: HeaderMap,
    index: Option<String>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let expression = index.as_deref().unwrap_or("_all");
    match opensearch_read_indices(&state, &auth, expression) {
        Ok(indices) => json_response(
            StatusCode::OK,
            &json!({ "_shards": { "total": indices.len(), "successful": indices.len(), "failed": 0 } })
                .to_string(),
        ),
        Err(response) => response.into_response(),
    }
}

