fn opensearch_bulk_with_default_index(
    state: DataRestState,
    headers: HeaderMap,
    raw_query: Option<String>,
    body: Bytes,
) -> Response {
    if let Err(response) = opensearch_refresh_query(raw_query.as_deref()) {
        return response.into_response();
    }
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let body = match std::str::from_utf8(&body) {
        Ok(value) => value,
        Err(_) => {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "bulk body must be utf-8 ndjson",
            );
        }
    };
    let lines = body
        .lines()
        .filter(|line| !line.trim().is_empty())
        .collect::<Vec<_>>();
    let mut items = Vec::new();
    let mut errors = false;
    let mut line_index = 0;
    while line_index < lines.len() {
        let action = match serde_json::from_str::<Value>(lines[line_index]) {
            Ok(value) => value,
            Err(_) => {
                return error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "bulk action line must be json",
                );
            }
        };
        line_index += 1;
        let (op, meta) = match opensearch_bulk_action(&action) {
            Ok(value) => value,
            Err(response) => return response.into_response(),
        };
        let index = meta
            .get("_index")
            .and_then(Value::as_str)
            .unwrap_or(&state.collection);
        let id = meta.get("_id").and_then(Value::as_str);
        if op == "delete" {
            let Some(id) = id else {
                errors = true;
                items.push(opensearch_bulk_item_error(
                    op,
                    index,
                    None,
                    400,
                    "invalid_argument",
                    "bulk action metadata requires _id",
                ));
                continue;
            };
            let target = match opensearch_write_index(&state, &auth, index) {
                Ok(value) => value,
                Err(response) => return response.into_response(),
            };
            let deleted = match state.kernel.data().search_delete(
                &auth,
                &state.workspace,
                &target,
                id.as_bytes(),
            ) {
                Ok(value) => value,
                Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
            };
            items.push(json!({
                op: {
                    "_index": index,
                    "_id": id,
                    "status": if deleted { 200 } else { 404 },
                    "result": if deleted { "deleted" } else { "not_found" }
                }
            }));
            errors |= !deleted;
            continue;
        }
        if line_index >= lines.len() {
            return error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "bulk index, create, and update actions require a source line",
            );
        }
        let source = match serde_json::from_str::<Value>(lines[line_index]) {
            Ok(value) => value,
            Err(_) => {
                return error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "bulk source line must be json",
                );
            }
        };
        line_index += 1;
        let Some(id) = id else {
            errors = true;
            items.push(opensearch_bulk_item_error(
                op,
                index,
                None,
                400,
                "invalid_argument",
                "bulk action metadata requires _id",
            ));
            continue;
        };
        let target = match opensearch_write_index(&state, &auth, index) {
            Ok(value) => value,
            Err(response) => return response.into_response(),
        };
        if op == "update" {
            let Some(doc_value) = source.get("doc") else {
                errors = true;
                items.push(opensearch_bulk_item_error(
                    op,
                    index,
                    Some(id),
                    400,
                    "invalid_argument",
                    "bulk update source requires doc",
                ));
                continue;
            };
            let update_doc = match opensearch_document(doc_value) {
                Ok(value) => value,
                Err(_) => {
                    errors = true;
                    items.push(opensearch_bulk_item_error(
                        op,
                        index,
                        Some(id),
                        400,
                        "invalid_argument",
                        "bulk update doc must be a valid document object",
                    ));
                    continue;
                }
            };
            let existing = match state.kernel.data().search_get(
                &auth,
                &state.workspace,
                &target,
                id.as_bytes(),
            ) {
                Ok(value) => value,
                Err(err) => return hosted_error_response(StatusCode::FORBIDDEN, err),
            };
            let doc_as_upsert = source
                .get("doc_as_upsert")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            let created = existing.is_none();
            let mut merged = match existing {
                Some(value) => value,
                None if doc_as_upsert => loom_core::Document::new(),
                None => {
                    errors = true;
                    items.push(json!({
                        op: {
                            "_index": index,
                            "_id": id,
                            "status": 404,
                            "result": "not_found"
                        }
                    }));
                    continue;
                }
            };
            merged.extend(update_doc);
            if let Err(err) = state.kernel.data().search_index(
                &auth,
                &state.workspace,
                &target,
                id.as_bytes().to_vec(),
                merged,
            ) {
                return hosted_error_response(StatusCode::FORBIDDEN, err);
            }
            items.push(json!({
                op: {
                    "_index": index,
                    "_id": id,
                    "status": if created { 201 } else { 200 },
                    "result": if created { "created" } else { "updated" }
                }
            }));
            continue;
        }
        let doc = match opensearch_document(&source) {
            Ok(value) => value,
            Err(_) => {
                errors = true;
                items.push(opensearch_bulk_item_error(
                    op,
                    index,
                    Some(id),
                    400,
                    "invalid_argument",
                    "bulk source must be a valid document object",
                ));
                continue;
            }
        };
        if let Err(err) = state.kernel.data().search_index(
            &auth,
            &state.workspace,
            &target,
            id.as_bytes().to_vec(),
            doc,
        ) {
            return hosted_error_response(StatusCode::FORBIDDEN, err);
        }
        items.push(json!({
            op: {
                "_index": index,
                "_id": id,
                "status": 201,
                "result": "created"
            }
        }));
    }
    json_response(
        StatusCode::OK,
        &json!({ "took": 0, "errors": errors, "items": items }).to_string(),
    )
}

async fn columnar_post_action(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(dataset_action): Path<String>,
    body: Bytes,
) -> Response {
    if let Some(dataset) = dataset_action.strip_suffix(":compact") {
        columnar_compact(State(state), headers, Path(dataset.to_string())).await
    } else if let Some(dataset) = dataset_action.strip_suffix(":select") {
        columnar_select(State(state), headers, Path(dataset.to_string()), body).await
    } else if let Some(dataset) = dataset_action.strip_suffix(":aggregate") {
        columnar_aggregate(State(state), headers, Path(dataset.to_string()), body).await
    } else {
        error_response(
            StatusCode::NOT_FOUND,
            Code::NotFound,
            "unsupported columnar action",
        )
    }
}

