async fn columnar_prepare_arrow_ipc_result(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(dataset): Path<String>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    if let Err(response) = columnar_dataset_matches(&state, &dataset) {
        return response.into_response();
    }
    let workspace_id = match hosted_workspace_id(&state.kernel, &auth, &state.workspace) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    if let Err(err) = state
        .kernel
        .data()
        .columnar_source_digest(&auth, &state.workspace, &dataset)
    {
        return hosted_error_response(StatusCode::FORBIDDEN, err);
    }
    let handle = match state.result_handles.lock() {
        Ok(mut handles) => handles.insert_resource(
            &auth,
            "columnar.arrow-ipc",
            Some(dataset),
            vec![ServedResultScope::new(
                workspace_id,
                FacetKind::Columnar,
                AclRight::Read,
            )],
            Duration::from_secs(300),
        ),
        Err(_) => Err(LoomError::new(
            Code::Internal,
            "served result registry is unavailable",
        )),
    };
    let handle = match handle {
        Ok(handle) => handle,
        Err(err) => return loom_error_response(StatusCode::INTERNAL_SERVER_ERROR, err),
    };
    json_response(
        StatusCode::ACCEPTED,
        &json!({
            "handle": handle,
            "format": "arrow-ipc",
            "href": format!("/_loom/results/{handle}")
        })
        .to_string(),
    )
}

async fn columnar_read_result_handle(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(handle): Path<String>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let record = match state.result_handles.lock() {
        Ok(mut handles) => {
            handles.authorize_and_remove(&state.kernel, &handle, &auth, "columnar.arrow-ipc")
        }
        Err(_) => Err(LoomError::new(
            Code::Internal,
            "served result registry is unavailable",
        )),
    };
    let record = match record {
        Ok(record) => record,
        Err(err) => return served_result_error_response(err),
    };
    let Some(dataset) = record.resource else {
        return served_result_not_found();
    };
    match state
        .kernel
        .data()
        .columnar_export_arrow_ipc(&auth, &state.workspace, &dataset)
    {
        Ok(bytes) => response(
            StatusCode::OK,
            "application/vnd.apache.arrow.stream",
            Body::from(bytes),
        ),
        Err(err) => columnar_transfer_error_response(err),
    }
}

async fn columnar_close_result_handle(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    Path(handle): Path<String>,
) -> Response {
    let auth = match hosted_auth(&headers, state.auth_policy) {
        Ok(auth) => auth,
        Err(response) => return response.into_response(),
    };
    let closed = match state.result_handles.lock() {
        Ok(mut handles) => {
            handles.authorize_and_close(&state.kernel, &handle, &auth, "columnar.arrow-ipc")
        }
        Err(_) => Err(LoomError::new(
            Code::Internal,
            "served result registry is unavailable",
        )),
    };
    match closed {
        Ok(()) => json_response(StatusCode::OK, "{\"ok\":true}"),
        Err(err) => served_result_error_response(err),
    }
}

