fn dataframe_batch_json(batch: DataframeBatch) -> Value {
    json!({
        "columns": batch.columns.into_iter().map(|column| {
            json!({
                "name": column.name,
                "type": dataframe_column_type_name(column.column_type),
                "type_tag": column.column_type.tag(),
                "nullable": column.nullable
            })
        }).collect::<Vec<_>>(),
        "rows": batch.rows.into_iter().map(|row| {
            Value::Array(row.into_iter().map(dataframe_value_json).collect())
        }).collect::<Vec<_>>()
    })
}

fn dataframe_column_type_name(ty: ColumnType) -> &'static str {
    match ty {
        ColumnType::Int => "int",
        ColumnType::Float => "float",
        ColumnType::Text => "text",
        ColumnType::Bool => "bool",
        ColumnType::Bytes => "bytes",
        ColumnType::I8 => "i8",
        ColumnType::I16 => "i16",
        ColumnType::I32 => "i32",
        ColumnType::I128 => "i128",
        ColumnType::U8 => "u8",
        ColumnType::U16 => "u16",
        ColumnType::U32 => "u32",
        ColumnType::U64 => "u64",
        ColumnType::U128 => "u128",
        ColumnType::F32 => "f32",
        ColumnType::Decimal => "decimal",
        ColumnType::Date => "date",
        ColumnType::Time => "time",
        ColumnType::Timestamp => "timestamp",
        ColumnType::Interval => "interval",
        ColumnType::Uuid => "uuid",
        ColumnType::Inet => "inet",
        ColumnType::Point => "point",
        ColumnType::List => "list",
        ColumnType::Map => "map",
    }
}

fn dataframe_value_json(value: DataValue) -> Value {
    match value {
        DataValue::Null => Value::Null,
        DataValue::Bool(value) => Value::Bool(value),
        DataValue::Int(value) => json!(value),
        DataValue::Float(value) => json!(value),
        DataValue::Text(value) => Value::String(value),
        DataValue::Bytes(value) => json!(hex_bytes(&value)),
        DataValue::I8(value) => json!(value),
        DataValue::I16(value) => json!(value),
        DataValue::I32(value) => json!(value),
        DataValue::I128(value) => json!(value.to_string()),
        DataValue::U8(value) => json!(value),
        DataValue::U16(value) => json!(value),
        DataValue::U32(value) => json!(value),
        DataValue::U64(value) => json!(value),
        DataValue::U128(value) => json!(value.to_string()),
        DataValue::F32(value) => json!(value),
        DataValue::Decimal { mantissa, scale } => {
            json!({ "mantissa": mantissa.to_string(), "scale": scale })
        }
        DataValue::Date(value) => json!(value),
        DataValue::Time(value) => json!(value),
        DataValue::Timestamp(value) => json!(value),
        DataValue::Interval { months, micros } => json!({ "months": months, "micros": micros }),
        DataValue::Uuid(value) => json!(value.to_string()),
        DataValue::Inet(value) => json!(value.to_string()),
        DataValue::Point { x, y } => json!({ "x": x, "y": y }),
        DataValue::List(values) => {
            Value::Array(values.into_iter().map(dataframe_value_json).collect())
        }
        DataValue::Map(values) => Value::Object(
            values
                .into_iter()
                .map(|(key, value)| (key, dataframe_value_json(value)))
                .collect(),
        ),
    }
}

