async fn structures_add_node(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    structure_node_write(state, headers, body, true).await
}

async fn structures_update_node(
    State(state): State<DataRestState>,
    headers: HeaderMap,
    body: Bytes,
) -> Response {
    structure_node_write(state, headers, body, false).await
}

async fn structure_node_write(
    state: DataRestState,
    headers: HeaderMap,
    body: Bytes,
    create: bool,
) -> Response {
    let (auth, value) = match auth_and_json(headers, state.auth_policy, &body) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let structure_id = match required_str(&value, "structure_id") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let node_id = match required_str(&value, "node_id") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let kind = match required_str(&value, "kind") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let label = match required_str(&value, "label") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let body_digest = match optional_str_ref(&value, "body_digest") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let entity_ref = match optional_str(&value, "entity_ref") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let expected_root = match optional_str_ref(&value, "expected_root") {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let workspace = match hosted_workspace_id(&state.kernel, &auth, &state.workspace) {
        Ok(value) => value,
        Err(response) => return response.into_response(),
    };
    let request = loom_pages::StructureNodeRequest {
        workspace_id: &state.collection,
        structure_id,
        node_id,
        kind,
        label,
        body_digest,
        entity_ref,
        expected_root,
    };
    let result = if create {
        state
            .kernel
            .rest()
            .structures_add_node(&auth, workspace, request)
    } else {
        state
            .kernel
            .rest()
            .structures_update_node(&auth, workspace, request)
    };
    match result {
        Ok(response) => json_response(
            StatusCode::from_u16(response.status).unwrap_or(StatusCode::OK),
            &json!(response.body).to_string(),
        ),
        Err(err) => rest_failure_response(err),
    }
}

