fn hosted_auth(headers: &HeaderMap, policy: HostedAuthPolicy) -> HostedHttpResult<HostedAuth> {
    let principal = header(headers, "x-loom-principal")?;
    let passphrase = header(headers, "x-loom-passphrase")?;
    let app_credential = hosted_api_key(headers)?;
    let external_credential = hosted_external_credential(headers)?;
    let session = header(headers, "x-loom-session")?.unwrap_or_else(|| "http".to_string());
    match (principal, passphrase, app_credential, external_credential) {
        (None, None, None, None) if policy == HostedAuthPolicy::OwnerOrPassphrase => {
            Ok(HostedAuth::unauthenticated())
        }
        (None, None, None, None) => Err(error_response(
            StatusCode::UNAUTHORIZED,
            Code::AuthenticationFailed,
            "hosted listener requires authentication",
        )
        .into()),
        (Some(principal), Some(passphrase), None, None) => {
            let principal = WorkspaceId::parse(&principal)
                .map_err(|err| loom_error_response(StatusCode::BAD_REQUEST, err))?;
            Ok(HostedAuth::passphrase(principal, passphrase, session))
        }
        (None, None, Some(app_credential), None) => {
            Ok(HostedAuth::app_credential(app_credential, session))
        }
        (None, None, None, Some(external_credential)) => {
            Ok(HostedAuth::verified_external(external_credential, session))
        }
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "supply one hosted credential: passphrase, API key, or verified external assertion",
        )
        .into()),
    }
}

fn hosted_api_key(headers: &HeaderMap) -> HostedHttpResult<Option<String>> {
    let candidates = [
        header(headers, "x-loom-api-key")?,
        header(headers, "x-api-key")?,
        header(headers, "api-key")?,
        header(headers, "x-pinecone-api-key")?,
        authorization_bearer(headers)?,
    ];
    let mut out = None;
    for value in candidates.into_iter().flatten() {
        if out.is_some() {
            return Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "only one API-key credential header may be supplied",
            )
            .into());
        }
        out = Some(value);
    }
    Ok(out)
}

fn hosted_external_credential(
    headers: &HeaderMap,
) -> HostedHttpResult<Option<VerifiedExternalCredential>> {
    let kind = header(headers, "x-loom-external-kind")?;
    let issuer = header(headers, "x-loom-external-issuer")?;
    let subject = header(headers, "x-loom-external-subject")?;
    let material_digest = header(headers, "x-loom-external-material-digest")?;
    let proof_kind = header(headers, "x-loom-external-proof-kind")?;
    let proof = header(headers, "x-loom-external-proof")?;
    let challenge = header(headers, "x-loom-external-challenge")?;
    let peer_certificate_der = match header(headers, INTERNAL_PEER_CERTIFICATE_DER_HEX)?.as_deref()
    {
        Some(value) => Some(
            hex_decode(value).map_err(|err| loom_error_response(StatusCode::BAD_REQUEST, err))?,
        ),
        None => None,
    };
    hosted_external_credential_from_parts(HostedExternalCredentialParts {
        kind,
        issuer,
        subject,
        material_digest,
        proof_kind,
        proof,
        challenge,
        peer_certificate_der: peer_certificate_der.as_deref(),
    })
    .map_err(|err| {
        let status = if err.code == Code::Unsupported {
            StatusCode::NOT_IMPLEMENTED
        } else {
            StatusCode::BAD_REQUEST
        };
        loom_error_response(status, err).into()
    })
}

fn authorization_bearer(headers: &HeaderMap) -> HostedHttpResult<Option<String>> {
    let Some(value) = header(headers, "authorization")? else {
        return Ok(None);
    };
    let Some(token) = value.strip_prefix("Bearer ") else {
        return Ok(None);
    };
    Ok(Some(token.to_string()))
}

