fn ticket_update_relation_removes_jsonrpc(
    params: &Value,
) -> Result<Vec<loom_tickets::TicketUpdateRelationRemoveRequest<'_>>, DataJsonRpcFailure> {
    let Some(relations) = params.get("relation_removes") else {
        return Ok(Vec::new());
    };
    if relations.is_null() {
        return Ok(Vec::new());
    }
    let Value::Array(relations) = relations else {
        return Err(DataJsonRpcFailure::Protocol(
            "relation_removes must be an array or null".to_string(),
        ));
    };
    relations
        .iter()
        .map(|relation| {
            let Value::Object(relation) = relation else {
                return Err(DataJsonRpcFailure::Protocol(
                    "relation_removes entries must be objects".to_string(),
                ));
            };
            let relation_id = match relation.get("relation_id") {
                Some(Value::String(relation_id)) => relation_id.as_str(),
                _ => {
                    return Err(DataJsonRpcFailure::Protocol(
                        "relation_removes.relation_id must be a string".to_string(),
                    ));
                }
            };
            Ok(loom_tickets::TicketUpdateRelationRemoveRequest { relation_id })
        })
        .collect()
}

