fn required_document_index_value_jsonrpc(
    params: &Value,
    name: &str,
) -> Result<DataValue, DataJsonRpcFailure> {
    let value = params
        .get(name)
        .ok_or_else(|| DataJsonRpcFailure::Protocol(format!("missing params.{name}")))?;
    match value {
        Value::Null => Ok(DataValue::Null),
        Value::Bool(value) => Ok(DataValue::Bool(*value)),
        Value::String(value) => Ok(DataValue::Text(value.clone())),
        Value::Number(number) => {
            if let Some(value) = number.as_i64() {
                Ok(DataValue::Int(value))
            } else if let Some(value) = number.as_u64() {
                Ok(DataValue::U64(value))
            } else {
                number
                    .as_f64()
                    .filter(|value| value.is_finite())
                    .map(DataValue::Float)
                    .ok_or_else(|| {
                        DataJsonRpcFailure::Protocol(format!(
                            "params.{name} must be a finite scalar"
                        ))
                    })
            }
        }
        Value::Array(_) | Value::Object(_) => Err(DataJsonRpcFailure::Protocol(format!(
            "params.{name} must be a scalar"
        ))),
    }
}

fn optional_string_jsonrpc(
    params: &Value,
    name: &str,
) -> Result<Option<String>, DataJsonRpcFailure> {
    match params.get(name) {
        Some(Value::Null) | None => Ok(None),
        Some(Value::String(value)) if value.is_empty() => Ok(None),
        Some(Value::String(value)) => Ok(Some(value.clone())),
        Some(_) => Err(DataJsonRpcFailure::Protocol(format!(
            "params.{name} must be string or null"
        ))),
    }
}

