struct StructureDecomposeRouteItem {
    node_id: String,
    project_id: String,
    ticket_type: Option<String>,
    fields: Option<Value>,
    policy_labels: Vec<String>,
}

fn structure_decompose_items_http(
    value: &Value,
) -> HostedHttpResult<Vec<StructureDecomposeRouteItem>> {
    let Some(items) = value.get("items") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "items must be an array",
        )
        .into());
    };
    let Some(items) = items.as_array() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "items must be an array",
        )
        .into());
    };
    items
        .iter()
        .map(|item| {
            let node_id = required_str(item, "node_id")?.to_string();
            let project_id = required_str(item, "project_id")?.to_string();
            let ticket_type = optional_str(item, "ticket_type")?;
            let fields = optional_object_value_http(item, "fields")?;
            let policy_labels = optional_string_array_http(item, "policy_labels")?;
            Ok(StructureDecomposeRouteItem {
                node_id,
                project_id,
                ticket_type,
                fields,
                policy_labels,
            })
        })
        .collect()
}

fn optional_object_value_http(value: &Value, name: &str) -> HostedHttpResult<Option<Value>> {
    match value.get(name) {
        Some(Value::Null) | None => Ok(None),
        Some(Value::Object(_)) => Ok(value.get(name).cloned()),
        Some(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must be an object"),
        )
        .into()),
    }
}

fn optional_string_array_http(value: &Value, name: &str) -> HostedHttpResult<Vec<String>> {
    let Some(items) = value.get(name) else {
        return Ok(Vec::new());
    };
    let Some(items) = items.as_array() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must be an array of strings"),
        )
        .into());
    };
    items
        .iter()
        .map(|item| {
            item.as_str().map(str::to_string).ok_or_else(|| {
                error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    &format!("{name} must be an array of strings"),
                )
                .into()
            })
        })
        .collect()
}

