fn lifecycle_gate_evaluations_http(
    value: &Value,
) -> HostedHttpResult<Vec<loom_lifecycle::LifecycleGateEvaluationInput>> {
    let Some(items) = value.get("gate_evaluations") else {
        return Ok(Vec::new());
    };
    let Some(items) = items.as_array() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "gate_evaluations must be an array",
        )
        .into());
    };
    items
        .iter()
        .map(|item| {
            let gate_id = required_str(item, "gate_id")?.to_string();
            let passed = bool_field(item, "passed")?;
            let principal_id = optional_str(item, "principal_id")?;
            let evidence_digest = optional_str(item, "evidence_digest")?;
            let evaluated_at_ms = required_u64(item, "evaluated_at_ms")?;
            Ok(loom_lifecycle::LifecycleGateEvaluationInput {
                gate_id,
                passed,
                principal_id,
                evidence_digest,
                evaluated_at_ms,
            })
        })
        .collect()
}

