fn time_series_point_json(point: crate::TimeSeriesPoint) -> Value {
    json!({
        "timestamp": point.timestamp,
        "value_hex": hex_bytes(&point.value)
    })
}

fn structured_time_series_point_json(point: crate::StructuredTimeSeriesPoint) -> Value {
    json!({
        "measurement": point.measurement,
        "tags": point.tags,
        "timestamp_ns": point.timestamp_ns,
        "fields": point.fields.into_iter().map(|(name, value)| (name, match value {
            TimeSeriesValue::Int(value) => json!(value),
            TimeSeriesValue::Float(value) => json!(value),
            TimeSeriesValue::Text(value) => json!(value),
            TimeSeriesValue::Bool(value) => json!(value),
            TimeSeriesValue::Bytes(value) => json!({ "bytes_hex": hex_bytes(&value) }),
        })).collect::<serde_json::Map<String, Value>>(),
    })
}

fn time_series_policy_json(policy: TimeSeriesPolicy) -> Value {
    json!({
        "query_start_ns": policy.query_start_ns,
        "rollups": policy.rollups.into_iter().map(|rollup| {
            json!({
                "name": rollup.name,
                "resolution_ns": rollup.resolution_ns,
                "aggregation": rollup.aggregation.as_str()
            })
        }).collect::<Vec<_>>()
    })
}

fn time_series_aggregation_field(value: &Value) -> HostedHttpResult<TimeSeriesAggregation> {
    match value.as_str() {
        Some("count") => Ok(TimeSeriesAggregation::Count),
        Some("sum") => Ok(TimeSeriesAggregation::Sum),
        Some("min") => Ok(TimeSeriesAggregation::Min),
        Some("max") => Ok(TimeSeriesAggregation::Max),
        Some("mean") => Ok(TimeSeriesAggregation::Mean),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unsupported time-series rollup aggregation",
        )
        .into()),
    }
}

type TimeSeriesPolicyFields = (Option<i64>, Vec<(String, i64, TimeSeriesAggregation)>);

const PROMETHEUS_COLLECTION: &str = "prometheus";
const OTLP_COLLECTION: &str = "otlp";

mod prometheus_proto {
    #[derive(Clone, PartialEq, prost::Message)]
    pub struct WriteRequest {
        #[prost(message, repeated, tag = "1")]
        pub timeseries: Vec<TimeSeries>,
    }

    #[derive(Clone, PartialEq, prost::Message)]
    pub struct TimeSeries {
        #[prost(message, repeated, tag = "1")]
        pub labels: Vec<Label>,
        #[prost(message, repeated, tag = "2")]
        pub samples: Vec<Sample>,
    }

    #[derive(Clone, PartialEq, prost::Message)]
    pub struct Label {
        #[prost(string, tag = "1")]
        pub name: String,
        #[prost(string, tag = "2")]
        pub value: String,
    }

    #[derive(Clone, PartialEq, prost::Message)]
    pub struct Sample {
        #[prost(double, tag = "1")]
        pub value: f64,
        #[prost(int64, tag = "2")]
        pub timestamp: i64,
    }
}

fn time_series_policy_fields(value: &Value) -> HostedHttpResult<TimeSeriesPolicyFields> {
    let query_start_ns = match value.get("query_start_ns") {
        None | Some(Value::Null) => None,
        Some(value) => Some(value.as_i64().ok_or_else(|| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "query_start_ns must be an integer or null",
            ))
        })?),
    };
    let rollups = match value.get("rollups") {
        None => Vec::new(),
        Some(Value::Array(rollups)) => rollups
            .iter()
            .map(|rollup| {
                Ok((
                    required_str(rollup, "name")?.to_string(),
                    required_i64(rollup, "resolution_ns")?,
                    time_series_aggregation_field(rollup.get("aggregation").ok_or_else(|| {
                        HostedHttpError::from(error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "missing field aggregation",
                        ))
                    })?)?,
                ))
            })
            .collect::<HostedHttpResult<_>>()?,
        _ => {
            return Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "time-series rollups must be an array",
            )
            .into());
        }
    };
    Ok((query_start_ns, rollups))
}

fn parse_influx_line_protocol(
    body: &str,
    precision: &str,
) -> HostedHttpResult<Vec<crate::StructuredTimeSeriesPoint>> {
    let multiplier = influx_precision_multiplier(precision)?;
    let mut points = Vec::new();
    for line in body.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let (series, rest) = split_unescaped_whitespace(line).ok_or_else(|| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "Influx line protocol missing fields",
            ))
        })?;
        let (fields, timestamp) = match split_unescaped_whitespace(rest) {
            Some((fields, timestamp)) => (fields, Some(timestamp.trim())),
            None => (rest.trim(), None),
        };
        let (measurement, tags) = parse_influx_series(series)?;
        let fields = parse_influx_fields(fields)?;
        let timestamp_ns = match timestamp {
            Some(timestamp) if !timestamp.is_empty() => timestamp
                .parse::<i64>()
                .ok()
                .and_then(|timestamp| timestamp.checked_mul(multiplier))
                .ok_or_else(|| {
                    HostedHttpError::from(error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        "invalid Influx timestamp",
                    ))
                })?,
            _ => current_unix_time_ns()?,
        };
        points.push(crate::StructuredTimeSeriesPoint {
            measurement,
            tags,
            timestamp_ns,
            fields,
        });
    }
    Ok(points)
}

fn influx_precision_multiplier(precision: &str) -> HostedHttpResult<i64> {
    match precision {
        "ns" => Ok(1),
        "u" | "us" => Ok(1_000),
        "ms" => Ok(1_000_000),
        "s" => Ok(1_000_000_000),
        "m" => Ok(60_000_000_000),
        "h" => Ok(3_600_000_000_000),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unsupported Influx precision",
        )
        .into()),
    }
}

fn current_unix_time_ns() -> HostedHttpResult<i64> {
    let duration = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map_err(|_| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "system clock is before UNIX epoch",
            ))
        })?;
    i64::try_from(duration.as_nanos()).map_err(|_| {
        error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "system clock exceeds i64 nanoseconds",
        )
        .into()
    })
}

fn parse_influx_series(series: &str) -> HostedHttpResult<(String, BTreeMap<String, String>)> {
    let parts = split_unescaped(series, ',');
    let Some(measurement) = parts.first() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "missing Influx measurement",
        )
        .into());
    };
    let measurement = unescape_influx_identifier(measurement);
    let mut tags = BTreeMap::new();
    for tag in parts.into_iter().skip(1) {
        let (name, value) = split_unescaped_once(tag, '=').ok_or_else(|| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "invalid Influx tag",
            ))
        })?;
        tags.insert(
            unescape_influx_identifier(name),
            unescape_influx_identifier(value),
        );
    }
    Ok((measurement, tags))
}

fn parse_influx_fields(fields: &str) -> HostedHttpResult<BTreeMap<String, TimeSeriesValue>> {
    let mut out = BTreeMap::new();
    for field in split_unescaped(fields, ',') {
        let (name, value) = split_unescaped_once(field, '=').ok_or_else(|| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "invalid Influx field",
            ))
        })?;
        out.insert(
            unescape_influx_identifier(name),
            parse_influx_field_value(value)?,
        );
    }
    Ok(out)
}

fn parse_influx_field_value(value: &str) -> HostedHttpResult<TimeSeriesValue> {
    if value.starts_with('"') && value.ends_with('"') && value.len() >= 2 {
        return Ok(TimeSeriesValue::Text(unescape_influx_string(
            &value[1..value.len() - 1],
        )));
    }
    match value {
        "t" | "T" | "true" | "True" | "TRUE" => return Ok(TimeSeriesValue::Bool(true)),
        "f" | "F" | "false" | "False" | "FALSE" => return Ok(TimeSeriesValue::Bool(false)),
        _ => {}
    }
    if let Some(value) = value.strip_suffix('i') {
        return value
            .parse::<i64>()
            .map(TimeSeriesValue::Int)
            .map_err(|_| influx_field_error());
    }
    if let Some(value) = value.strip_suffix('u') {
        return value
            .parse::<u64>()
            .ok()
            .and_then(|value| i64::try_from(value).ok())
            .map(TimeSeriesValue::Int)
            .ok_or_else(influx_field_error);
    }
    value
        .parse::<f64>()
        .ok()
        .filter(|value| value.is_finite())
        .map(TimeSeriesValue::Float)
        .ok_or_else(influx_field_error)
}

fn influx_field_error() -> HostedHttpError {
    error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        "invalid Influx field value",
    )
    .into()
}

fn split_unescaped_whitespace(value: &str) -> Option<(&str, &str)> {
    let mut escaped = false;
    let mut quoted = false;
    for (index, ch) in value.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == '"' {
            quoted = !quoted;
            continue;
        }
        if !quoted && ch.is_ascii_whitespace() {
            return Some((&value[..index], value[index..].trim_start()));
        }
    }
    None
}

fn split_unescaped_once(value: &str, delimiter: char) -> Option<(&str, &str)> {
    let mut escaped = false;
    for (index, ch) in value.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == delimiter {
            let next = index + ch.len_utf8();
            return Some((&value[..index], &value[next..]));
        }
    }
    None
}

fn split_unescaped(value: &str, delimiter: char) -> Vec<&str> {
    let mut out = Vec::new();
    let mut start = 0usize;
    let mut escaped = false;
    let mut quoted = false;
    for (index, ch) in value.char_indices() {
        if escaped {
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if ch == '"' {
            quoted = !quoted;
            continue;
        }
        if !quoted && ch == delimiter {
            out.push(&value[start..index]);
            start = index + ch.len_utf8();
        }
    }
    out.push(&value[start..]);
    out
}

fn unescape_influx_identifier(value: &str) -> String {
    let mut out = String::with_capacity(value.len());
    let mut escaped = false;
    for ch in value.chars() {
        if escaped {
            out.push(ch);
            escaped = false;
        } else if ch == '\\' {
            escaped = true;
        } else {
            out.push(ch);
        }
    }
    if escaped {
        out.push('\\');
    }
    out
}

fn unescape_influx_string(value: &str) -> String {
    let mut out = String::with_capacity(value.len());
    let mut escaped = false;
    for ch in value.chars() {
        if escaped {
            out.push(ch);
            escaped = false;
        } else if ch == '\\' {
            escaped = true;
        } else {
            out.push(ch);
        }
    }
    if escaped {
        out.push('\\');
    }
    out
}

fn prometheus_points_from_write_request(
    request: prometheus_proto::WriteRequest,
) -> HostedHttpResult<Vec<crate::StructuredTimeSeriesPoint>> {
    let mut points = Vec::new();
    for series in request.timeseries {
        let mut measurement = None;
        let mut tags = BTreeMap::new();
        for label in series.labels {
            if label.name == "__name__" {
                measurement = Some(label.value);
            } else if !label.name.is_empty() {
                tags.insert(label.name, label.value);
            }
        }
        let measurement = measurement.ok_or_else(|| {
            HostedHttpError::from(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "Prometheus series is missing __name__ label",
            ))
        })?;
        for sample in series.samples {
            if !sample.value.is_finite() {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "Prometheus sample values must be finite",
                )
                .into());
            }
            let timestamp_ns = sample.timestamp.checked_mul(1_000_000).ok_or_else(|| {
                HostedHttpError::from(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "Prometheus sample timestamp overflow",
                ))
            })?;
            points.push(crate::StructuredTimeSeriesPoint {
                measurement: measurement.clone(),
                tags: tags.clone(),
                timestamp_ns,
                fields: BTreeMap::from([(
                    "value".to_string(),
                    TimeSeriesValue::Float(sample.value),
                )]),
            });
        }
    }
    Ok(points)
}

#[derive(Clone, Debug)]
struct PrometheusSelector {
    measurement: String,
    tags: BTreeMap<String, String>,
}

fn prometheus_selector_from_query(
    query: &HashMap<String, String>,
) -> HostedHttpResult<PrometheusSelector> {
    let Some(selector) = query.get("query") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "missing Prometheus query",
        )
        .into());
    };
    parse_prometheus_selector(selector)
}

fn parse_prometheus_selector(selector: &str) -> HostedHttpResult<PrometheusSelector> {
    let selector = selector.trim();
    if let Some(open) = selector.find('{') {
        let close = selector.rfind('}').ok_or_else(prometheus_selector_error)?;
        if close + 1 != selector.len() {
            return Err(prometheus_selector_error());
        }
        let measurement = selector[..open].trim();
        let mut tags = BTreeMap::new();
        let labels = &selector[open + 1..close];
        if !labels.trim().is_empty() {
            for label in split_unescaped(labels, ',') {
                let (name, value) = split_unescaped_once(label.trim(), '=')
                    .ok_or_else(prometheus_selector_error)?;
                let value = value.trim();
                if !(value.starts_with('"') && value.ends_with('"') && value.len() >= 2) {
                    return Err(prometheus_selector_error());
                }
                tags.insert(
                    name.trim().to_string(),
                    unescape_influx_string(&value[1..value.len() - 1]),
                );
            }
        }
        if measurement.is_empty() {
            return Err(prometheus_selector_error());
        }
        Ok(PrometheusSelector {
            measurement: measurement.to_string(),
            tags,
        })
    } else if selector.is_empty() {
        Err(prometheus_selector_error())
    } else {
        Ok(PrometheusSelector {
            measurement: selector.to_string(),
            tags: BTreeMap::new(),
        })
    }
}

fn prometheus_selector_error() -> HostedHttpError {
    error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        "unsupported Prometheus selector",
    )
    .into()
}

fn prometheus_seconds_to_ns(value: &str) -> HostedHttpResult<i64> {
    let seconds = value.parse::<f64>().map_err(|_| {
        HostedHttpError::from(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "invalid Prometheus timestamp",
        ))
    })?;
    if !seconds.is_finite() {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "invalid Prometheus timestamp",
        )
        .into());
    }
    let nanos = seconds * 1_000_000_000.0;
    if nanos < i64::MIN as f64 || nanos > i64::MAX as f64 {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "Prometheus timestamp overflow",
        )
        .into());
    }
    Ok(nanos as i64)
}

fn prometheus_point_matches(
    point: &crate::StructuredTimeSeriesPoint,
    selector: &PrometheusSelector,
) -> bool {
    point.measurement == selector.measurement
        && selector
            .tags
            .iter()
            .all(|(name, value)| point.tags.get(name) == Some(value))
}

fn prometheus_metric_json(point: &crate::StructuredTimeSeriesPoint) -> Value {
    let mut metric = serde_json::Map::new();
    metric.insert("__name__".to_string(), json!(point.measurement));
    for (name, value) in &point.tags {
        metric.insert(name.clone(), json!(value));
    }
    Value::Object(metric)
}

fn prometheus_sample_json(point: &crate::StructuredTimeSeriesPoint) -> Option<Value> {
    let value = match point.fields.get("value")? {
        TimeSeriesValue::Int(value) => value.to_string(),
        TimeSeriesValue::Float(value) if value.is_finite() => value.to_string(),
        _ => return None,
    };
    Some(json!([point.timestamp_ns as f64 / 1_000_000_000.0, value]))
}

fn prometheus_vector_json(
    points: Vec<crate::StructuredTimeSeriesPoint>,
    selector: PrometheusSelector,
) -> Vec<Value> {
    let mut latest =
        BTreeMap::<(String, Vec<(String, String)>), crate::StructuredTimeSeriesPoint>::new();
    for point in points {
        if !prometheus_point_matches(&point, &selector) {
            continue;
        }
        let key = (
            point.measurement.clone(),
            point
                .tags
                .iter()
                .map(|(name, value)| (name.clone(), value.clone()))
                .collect(),
        );
        latest.insert(key, point);
    }
    latest
        .into_values()
        .filter_map(|point| {
            let sample = prometheus_sample_json(&point)?;
            Some(json!({ "metric": prometheus_metric_json(&point), "value": sample }))
        })
        .collect()
}

fn prometheus_matrix_json(
    points: Vec<crate::StructuredTimeSeriesPoint>,
    selector: PrometheusSelector,
) -> Vec<Value> {
    let mut series =
        BTreeMap::<(String, Vec<(String, String)>), Vec<crate::StructuredTimeSeriesPoint>>::new();
    for point in points {
        if !prometheus_point_matches(&point, &selector) {
            continue;
        }
        let key = (
            point.measurement.clone(),
            point
                .tags
                .iter()
                .map(|(name, value)| (name.clone(), value.clone()))
                .collect(),
        );
        series.entry(key).or_default().push(point);
    }
    series
        .into_values()
        .filter_map(|points| {
            let metric = prometheus_metric_json(points.first()?);
            let values = points
                .iter()
                .filter_map(prometheus_sample_json)
                .collect::<Vec<_>>();
            Some(json!({ "metric": metric, "values": values }))
        })
        .collect()
}

fn otlp_metric_points(value: &Value) -> HostedHttpResult<Vec<crate::StructuredTimeSeriesPoint>> {
    let mut points = Vec::new();
    let Some(Value::Array(resource_metrics)) = value.get("resourceMetrics") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "OTLP metrics payload must contain resourceMetrics",
        )
        .into());
    };
    for resource_metric in resource_metrics {
        let resource_tags = otlp_resource_tags(resource_metric)?;
        let Some(Value::Array(scope_metrics)) = resource_metric.get("scopeMetrics") else {
            continue;
        };
        for scope_metric in scope_metrics {
            let Some(Value::Array(metrics)) = scope_metric.get("metrics") else {
                continue;
            };
            for metric in metrics {
                let name = required_str(metric, "name")?.to_string();
                for datapoint in otlp_metric_datapoints(metric) {
                    let timestamp_ns = otlp_timestamp_ns(datapoint)?;
                    let value = otlp_datapoint_value(datapoint)?;
                    let mut tags = resource_tags.clone();
                    tags.extend(otlp_attributes(datapoint.get("attributes"))?);
                    points.push(crate::StructuredTimeSeriesPoint {
                        measurement: name.clone(),
                        tags,
                        timestamp_ns,
                        fields: BTreeMap::from([("value".to_string(), value)]),
                    });
                }
            }
        }
    }
    Ok(points)
}

fn otlp_resource_tags(value: &Value) -> HostedHttpResult<BTreeMap<String, String>> {
    match value
        .get("resource")
        .and_then(|resource| resource.get("attributes"))
    {
        Some(attributes) => otlp_attributes(Some(attributes)),
        None => Ok(BTreeMap::new()),
    }
}

fn otlp_metric_datapoints(metric: &Value) -> Vec<&Value> {
    for kind in ["gauge", "sum"] {
        if let Some(Value::Array(points)) =
            metric.get(kind).and_then(|value| value.get("dataPoints"))
        {
            return points.iter().collect();
        }
    }
    Vec::new()
}

fn otlp_timestamp_ns(value: &Value) -> HostedHttpResult<i64> {
    match value.get("timeUnixNano") {
        Some(Value::String(value)) => value.parse::<i64>().map_err(|_| otlp_timestamp_error()),
        Some(Value::Number(value)) => value.as_i64().ok_or_else(otlp_timestamp_error),
        _ => Err(otlp_timestamp_error()),
    }
}

fn otlp_timestamp_error() -> HostedHttpError {
    error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        "OTLP datapoint is missing a valid timeUnixNano",
    )
    .into()
}

fn otlp_datapoint_value(value: &Value) -> HostedHttpResult<TimeSeriesValue> {
    if let Some(value) = value.get("asDouble").and_then(Value::as_f64)
        && value.is_finite()
    {
        return Ok(TimeSeriesValue::Float(value));
    }
    if let Some(value) = value.get("asInt") {
        return match value {
            Value::String(value) => value
                .parse::<i64>()
                .map(TimeSeriesValue::Int)
                .map_err(|_| otlp_value_error()),
            Value::Number(value) => value
                .as_i64()
                .map(TimeSeriesValue::Int)
                .ok_or_else(otlp_value_error),
            _ => Err(otlp_value_error()),
        };
    }
    Err(otlp_value_error())
}

fn otlp_value_error() -> HostedHttpError {
    error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        "OTLP datapoint is missing a supported numeric value",
    )
    .into()
}

fn otlp_attributes(value: Option<&Value>) -> HostedHttpResult<BTreeMap<String, String>> {
    let Some(Value::Array(attributes)) = value else {
        return Ok(BTreeMap::new());
    };
    let mut tags = BTreeMap::new();
    for attribute in attributes {
        let key = required_str(attribute, "key")?.to_string();
        let value = otlp_attribute_value(attribute.get("value"))?;
        tags.insert(key, value);
    }
    Ok(tags)
}

fn otlp_attribute_value(value: Option<&Value>) -> HostedHttpResult<String> {
    let Some(Value::Object(value)) = value else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "OTLP attribute is missing value",
        )
        .into());
    };
    if let Some(value) = value.get("stringValue").and_then(Value::as_str) {
        return Ok(value.to_string());
    }
    if let Some(value) = value.get("boolValue").and_then(Value::as_bool) {
        return Ok(value.to_string());
    }
    if let Some(value) = value.get("intValue") {
        return match value {
            Value::String(value) => Ok(value.clone()),
            Value::Number(value) => {
                value
                    .as_i64()
                    .map(|value| value.to_string())
                    .ok_or_else(|| {
                        HostedHttpError::from(error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "OTLP int attribute is out of range",
                        ))
                    })
            }
            _ => Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "unsupported OTLP int attribute",
            )
            .into()),
        };
    }
    if let Some(value) = value.get("doubleValue").and_then(Value::as_f64)
        && value.is_finite()
    {
        return Ok(value.to_string());
    }
    Err(error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        "unsupported OTLP attribute value",
    )
    .into())
}

fn structured_time_series_point_field(
    value: &Value,
) -> HostedHttpResult<crate::StructuredTimeSeriesPoint> {
    let measurement = required_str(value, "measurement")?.to_string();
    let timestamp_ns = required_i64(value, "timestamp_ns")?;
    let tags = match value.get("tags") {
        None => BTreeMap::new(),
        Some(Value::Object(tags)) => tags
            .iter()
            .map(|(name, value)| {
                value
                    .as_str()
                    .map(|value| (name.clone(), value.to_string()))
                    .ok_or_else(|| {
                        error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "time-series tag values must be strings",
                        )
                        .into()
                    })
            })
            .collect::<HostedHttpResult<BTreeMap<_, _>>>()?,
        _ => {
            return Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "time-series tags must be an object",
            )
            .into());
        }
    };
    let Some(Value::Object(fields)) = value.get("fields") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "time-series fields must be an object",
        )
        .into());
    };
    let fields = fields
        .iter()
        .map(|(name, value)| {
            let value = match value {
                Value::Bool(value) => TimeSeriesValue::Bool(*value),
                Value::String(value) => TimeSeriesValue::Text(value.clone()),
                Value::Number(value) if let Some(value) = value.as_i64() => {
                    TimeSeriesValue::Int(value)
                }
                Value::Number(value) => value
                    .as_f64()
                    .filter(|value| value.is_finite())
                    .map(TimeSeriesValue::Float)
                    .ok_or_else(|| {
                        HostedHttpError::from(error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "time-series fields must be finite numbers",
                        ))
                    })?,
                Value::Object(value) => TimeSeriesValue::Bytes(required_hex_field(
                    &Value::Object(value.clone()),
                    "bytes_hex",
                )?),
                _ => {
                    return Err(error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        "unsupported time-series field value",
                    )
                    .into());
                }
            };
            Ok((name.clone(), value))
        })
        .collect::<HostedHttpResult<BTreeMap<_, _>>>()?;
    Ok(crate::StructuredTimeSeriesPoint {
        measurement,
        tags,
        timestamp_ns,
        fields,
    })
}

fn props_field(value: &Value) -> HostedHttpResult<graph::Props> {
    match value.get("props") {
        Some(Value::Object(props)) => props
            .iter()
            .map(|(key, value)| {
                graph_value_from_json(value)
                    .map(|value| (key.clone(), value))
                    .map_err(|message| {
                        error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            &format!("props.{key}: {message}"),
                        )
                        .into()
                    })
            })
            .collect(),
        Some(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "props must be an object",
        )
        .into()),
        None => Ok(graph::Props::new()),
    }
}

fn graph_mutation_plan_field(value: &Value) -> HostedHttpResult<graph::GraphMutationPlan> {
    if let Some(query) = value.get("query") {
        let Some(query) = query.as_str() else {
            return Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "query must be a string",
            )
            .into());
        };
        let identity = graph_mutation_identity_field(value)?;
        return graph::GraphMutationPlan::parse_opencypher(query, &identity)
            .map_err(|err| error_response(StatusCode::BAD_REQUEST, err.code, &err.message).into());
    }
    let mutations = value
        .get("mutations")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "mutations must be an array",
            )
        })?;
    let mut out = Vec::new();
    for mutation in mutations {
        out.push(graph_mutation_from_json(mutation)?);
    }
    Ok(graph::GraphMutationPlan::new(out))
}

fn graph_query_field(value: &Value) -> HostedHttpResult<graph::GraphQuery> {
    let query = required_str(value, "query")?;
    graph::GraphQuery::parse_opencypher(query)
        .map_err(|err| error_response(StatusCode::BAD_REQUEST, err.code, &err.message).into())
}

fn graph_mutation_identity_field(value: &Value) -> HostedHttpResult<graph::GraphMutationIdentity> {
    let Some(identity) = value.get("identity") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "identity is required",
        )
        .into());
    };
    let Value::Object(_) = identity else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "identity must be an object",
        )
        .into());
    };
    Ok(graph::GraphMutationIdentity::new(
        graph_identity_map(identity, "nodes")?,
        graph_identity_map(identity, "edges")?,
    ))
}

fn graph_identity_map(value: &Value, name: &str) -> HostedHttpResult<BTreeMap<String, String>> {
    match value.get(name) {
        Some(Value::Object(items)) => items
            .iter()
            .map(|(binding, id)| {
                id.as_str()
                    .map(|id| (binding.clone(), id.to_string()))
                    .ok_or_else(|| {
                        error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            &format!("identity.{name} values must be strings"),
                        )
                        .into()
                    })
            })
            .collect(),
        Some(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("identity.{name} must be an object"),
        )
        .into()),
        None => Ok(BTreeMap::new()),
    }
}

fn graph_mutation_from_json(value: &Value) -> HostedHttpResult<graph::GraphMutation> {
    let op = required_str(value, "op")?;
    match op {
        "create_node" => Ok(graph::GraphMutation::CreateNode {
            id: required_str(value, "id")?.to_string(),
            labels: labels_field(value)?,
            props: props_field(value)?,
        }),
        "create_edge" => Ok(graph::GraphMutation::CreateEdge {
            id: required_str(value, "id")?.to_string(),
            src: required_str(value, "src")?.to_string(),
            dst: required_str(value, "dst")?.to_string(),
            label: required_str(value, "label")?.to_string(),
            props: props_field(value)?,
        }),
        "merge_node" => Ok(graph::GraphMutation::MergeNode {
            id: required_str(value, "id")?.to_string(),
            labels: labels_field(value)?,
            props: props_field(value)?,
        }),
        "merge_edge" => Ok(graph::GraphMutation::MergeEdge {
            id: required_str(value, "id")?.to_string(),
            src: required_str(value, "src")?.to_string(),
            dst: required_str(value, "dst")?.to_string(),
            label: required_str(value, "label")?.to_string(),
            props: props_field(value)?,
        }),
        "set_node_property" => Ok(graph::GraphMutation::SetNodeProperty {
            id: required_str(value, "id")?.to_string(),
            property: required_str(value, "property")?.to_string(),
            value: graph_value_json_field(value, "value")?,
        }),
        "set_edge_property" => Ok(graph::GraphMutation::SetEdgeProperty {
            id: required_str(value, "id")?.to_string(),
            property: required_str(value, "property")?.to_string(),
            value: graph_value_json_field(value, "value")?,
        }),
        "remove_node_property" => Ok(graph::GraphMutation::RemoveNodeProperty {
            id: required_str(value, "id")?.to_string(),
            property: required_str(value, "property")?.to_string(),
        }),
        "remove_edge_property" => Ok(graph::GraphMutation::RemoveEdgeProperty {
            id: required_str(value, "id")?.to_string(),
            property: required_str(value, "property")?.to_string(),
        }),
        "delete_node" => Ok(graph::GraphMutation::DeleteNode {
            id: required_str(value, "id")?.to_string(),
            detach: value
                .get("detach")
                .and_then(Value::as_bool)
                .unwrap_or(false),
        }),
        "delete_edge" => Ok(graph::GraphMutation::DeleteEdge {
            id: required_str(value, "id")?.to_string(),
        }),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unsupported graph mutation op",
        )
        .into()),
    }
}

fn labels_field(value: &Value) -> HostedHttpResult<BTreeSet<String>> {
    match value.get("labels") {
        Some(Value::Array(labels)) => labels
            .iter()
            .map(|label| {
                label.as_str().map(str::to_string).ok_or_else(|| {
                    error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        "labels must be strings",
                    )
                    .into()
                })
            })
            .collect(),
        Some(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "labels must be an array",
        )
        .into()),
        None => Ok(BTreeSet::new()),
    }
}

fn graph_value_json_field(value: &Value, name: &str) -> HostedHttpResult<graph::GraphValue> {
    let Some(value) = value.get(name) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} is required"),
        )
        .into());
    };
    graph_value_from_json(value).map_err(|message| {
        error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name}: {message}"),
        )
        .into()
    })
}

fn graph_value_from_json(value: &Value) -> Result<graph::GraphValue, String> {
    match value {
        Value::Null => Ok(graph::GraphValue::Null),
        Value::Bool(value) => Ok(graph::GraphValue::Bool(*value)),
        Value::Number(value) => {
            if let Some(value) = value.as_i64() {
                Ok(graph::GraphValue::Int(value))
            } else if let Some(value) = value.as_f64() {
                if value.is_finite() {
                    Ok(graph::GraphValue::Float(value))
                } else {
                    Err("float must be finite".to_string())
                }
            } else {
                Err("number is out of range".to_string())
            }
        }
        Value::String(value) => Ok(graph::GraphValue::Text(value.clone())),
        Value::Object(object) if object.len() == 1 && object.contains_key("bytes") => {
            let Some(raw) = object.get("bytes").and_then(Value::as_str) else {
                return Err("bytes must be a hex string".to_string());
            };
            decode_hex(raw).map(graph::GraphValue::Bytes)
        }
        Value::Object(object) if object.len() == 1 && object.contains_key("geometry") => {
            graph_geometry_from_json(
                object
                    .get("geometry")
                    .ok_or_else(|| "geometry is required".to_string())?,
            )
            .map(graph::GraphValue::Geometry)
        }
        Value::Array(values) => values
            .iter()
            .map(graph_value_from_json)
            .collect::<Result<Vec<_>, _>>()
            .map(graph::GraphValue::List),
        Value::Object(object) => object
            .iter()
            .map(|(key, value)| graph_value_from_json(value).map(|value| (key.clone(), value)))
            .collect::<Result<BTreeMap<_, _>, _>>()
            .map(graph::GraphValue::Map),
    }
}

fn graph_value_json(value: graph::GraphValue) -> Value {
    match value {
        graph::GraphValue::Null => Value::Null,
        graph::GraphValue::Bool(value) => Value::Bool(value),
        graph::GraphValue::Int(value) => json!(value),
        graph::GraphValue::Float(value) => serde_json::Number::from_f64(value)
            .map(Value::Number)
            .unwrap_or(Value::Null),
        graph::GraphValue::Text(value) => Value::String(value),
        graph::GraphValue::Bytes(value) => json!({ "bytes": hex_bytes(&value) }),
        graph::GraphValue::List(values) => {
            Value::Array(values.into_iter().map(graph_value_json).collect())
        }
        graph::GraphValue::Map(values) => Value::Object(
            values
                .into_iter()
                .map(|(key, value)| (key, graph_value_json(value)))
                .collect(),
        ),
        graph::GraphValue::Geometry(value) => json!({ "geometry": graph_geometry_json(value) }),
    }
}

fn graph_geometry_from_json(value: &Value) -> Result<graph::GraphGeometry, String> {
    let Value::Object(object) = value else {
        return Err("geometry must be an object".to_string());
    };
    let kind = object
        .get("type")
        .and_then(Value::as_str)
        .ok_or_else(|| "geometry.type is required".to_string())?;
    match kind {
        "point" => {
            let crs = object
                .get("crs")
                .and_then(Value::as_str)
                .ok_or_else(|| "geometry.crs is required".to_string())
                .and_then(|value| graph::GraphCrs::parse(value).map_err(|err| err.to_string()))?;
            let x = finite_json_float(object, "x")?;
            let y = finite_json_float(object, "y")?;
            let z = match object.get("z") {
                None | Some(Value::Null) => None,
                Some(_) => Some(finite_json_float(object, "z")?),
            };
            graph::GraphGeometry::point(crs, x, y, z).map_err(|err| err.to_string())
        }
        _ => Err("unsupported geometry.type".to_string()),
    }
}

fn finite_json_float(object: &serde_json::Map<String, Value>, key: &str) -> Result<f64, String> {
    let value = object
        .get(key)
        .and_then(Value::as_f64)
        .ok_or_else(|| format!("geometry.{key} must be a number"))?;
    if value.is_finite() {
        Ok(value)
    } else {
        Err(format!("geometry.{key} must be finite"))
    }
}

fn graph_geometry_json(value: graph::GraphGeometry) -> Value {
    match value {
        graph::GraphGeometry::Point(point) => {
            let mut object = serde_json::Map::new();
            object.insert("type".to_string(), Value::String("point".to_string()));
            object.insert(
                "crs".to_string(),
                Value::String(point.crs.as_str().to_string()),
            );
            object.insert("x".to_string(), json!(point.x));
            object.insert("y".to_string(), json!(point.y));
            if let Some(z) = point.z {
                object.insert("z".to_string(), json!(z));
            }
            Value::Object(object)
        }
    }
}

fn props_json(props: graph::Props) -> Value {
    Value::Object(
        props
            .into_iter()
            .map(|(key, value)| (key, graph_value_json(value)))
            .collect(),
    )
}

fn graph_query_value_json(value: graph::GraphQueryValue) -> Value {
    match value {
        graph::GraphQueryValue::Null => json!({ "type": "null" }),
        graph::GraphQueryValue::Scalar(value) => {
            json!({ "type": "scalar", "value": graph_value_json(value) })
        }
        graph::GraphQueryValue::Node(node) => json!({
            "type": "node",
            "id": node.id,
            "labels": node.labels.into_iter().collect::<Vec<_>>(),
            "props": props_json(node.props),
        }),
        graph::GraphQueryValue::Edge(edge) => json!({
            "type": "edge",
            "id": edge.id,
            "src": edge.src,
            "dst": edge.dst,
            "label": edge.label,
            "props": props_json(edge.props),
        }),
        graph::GraphQueryValue::Path(path) => json!({
            "type": "path",
            "nodes": path
                .nodes
                .into_iter()
                .map(|node| graph_query_value_json(graph::GraphQueryValue::Node(node)))
                .collect::<Vec<_>>(),
            "edges": path
                .edges
                .into_iter()
                .map(|edge| graph_query_value_json(graph::GraphQueryValue::Edge(edge)))
                .collect::<Vec<_>>(),
        }),
        graph::GraphQueryValue::List(values) => json!({
            "type": "list",
            "values": values.into_iter().map(graph_query_value_json).collect::<Vec<_>>(),
        }),
        graph::GraphQueryValue::Map(values) => json!({
            "type": "map",
            "values": values
                .into_iter()
                .map(|(key, value)| (key, graph_query_value_json(value)))
                .collect::<BTreeMap<_, _>>(),
        }),
    }
}

fn graph_query_result_json(result: graph::GraphQueryResult) -> Value {
    json!({
        "rows": result
            .rows
            .into_iter()
            .map(|row| {
                Value::Object(
                    row.into_iter()
                        .map(|(key, value)| (key, graph_query_value_json(value)))
                        .collect(),
                )
            })
            .collect::<Vec<_>>()
    })
}

fn graph_index_entity_json(entity: graph::GraphIndexEntity) -> &'static str {
    match entity {
        graph::GraphIndexEntity::Node => "node",
        graph::GraphIndexEntity::Edge => "edge",
    }
}

fn graph_index_status_json(status: graph::GraphIndexStatus) -> &'static str {
    match status {
        graph::GraphIndexStatus::NotBuilt => "not_built",
        graph::GraphIndexStatus::Stale => "stale",
        graph::GraphIndexStatus::Ready => "ready",
    }
}

fn graph_property_index_json(index: graph::GraphPropertyIndex) -> Value {
    json!({
        "name": index.name,
        "entity": graph_index_entity_json(index.entity),
        "property": index.property,
    })
}

fn graph_spatial_index_json(index: graph::GraphSpatialIndex) -> Value {
    json!({
        "name": index.name,
        "entity": graph_index_entity_json(index.entity),
        "property": index.property,
    })
}

fn graph_query_explain_json(explain: graph::GraphQueryExplain) -> Value {
    json!({
        "indexes": explain
            .indexes
            .into_iter()
            .map(|report| json!({
                "index": graph_property_index_json(report.index),
                "status": graph_index_status_json(report.status),
                "entries": report.entries,
                "distinct_values": report.distinct_values,
            }))
            .collect::<Vec<_>>(),
        "spatial_indexes": explain
            .spatial_indexes
            .into_iter()
            .map(|report| json!({
                "index": graph_spatial_index_json(report.index),
                "status": graph_index_status_json(report.status),
                "entries": report.entries,
            }))
            .collect::<Vec<_>>(),
        "selections": explain
            .selections
            .into_iter()
            .map(|selection| json!({
                "binding": selection.binding,
                "entity": graph_index_entity_json(selection.entity),
                "property": selection.property,
                "index": selection.index,
                "status": graph_index_status_json(selection.status),
                "reason": selection.reason,
            }))
            .collect::<Vec<_>>(),
        "fallback_scan": explain.fallback_scan,
    })
}

fn columnar_dataset_matches(state: &DataRestState, dataset: &str) -> HostedHttpResult<()> {
    if state.collection == dataset {
        Ok(())
    } else {
        Err(error_response(
            StatusCode::NOT_FOUND,
            Code::NotFound,
            "dataset is not served by this listener",
        )
        .into())
    }
}

fn served_result_not_found() -> Response {
    error_response(
        StatusCode::NOT_FOUND,
        Code::NotFound,
        "served result handle was not found",
    )
}

fn served_result_error_response(err: LoomError) -> Response {
    if err.code == Code::NotFound {
        served_result_not_found()
    } else {
        loom_error_response(StatusCode::FORBIDDEN, err)
    }
}

fn hosted_workspace_id(
    kernel: &HostedKernel,
    auth: &HostedAuth,
    workspace: &str,
) -> HostedHttpResult<WorkspaceId> {
    kernel
        .read(auth, |loom| {
            loom.registry()
                .open(&WsSelector::Name(workspace.to_string()))
        })
        .map_err(|err| loom_error_response(StatusCode::FORBIDDEN, err).into())
}

fn columnar_jsonrpc_dataset<'a>(
    params: &'a Value,
    state: &'a DataRestState,
) -> Result<&'a str, DataJsonRpcFailure> {
    match params.get("dataset") {
        Some(Value::String(dataset)) if dataset == &state.collection => Ok(dataset),
        Some(Value::String(_)) => Err(DataJsonRpcFailure::Protocol(
            "params.dataset is not served by this listener".to_string(),
        )),
        Some(_) => Err(DataJsonRpcFailure::Protocol(
            "params.dataset must be a string".to_string(),
        )),
        None => Ok(&state.collection),
    }
}

fn columnar_columns_field(value: &Value) -> HostedHttpResult<Vec<(String, ColumnType)>> {
    let Some(columns) = value.get("columns").and_then(Value::as_array) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "columns must be an array",
        )
        .into());
    };
    columns
        .iter()
        .map(|column| {
            let Some(column) = column.as_object() else {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "columns entries must be objects",
                )
                .into());
            };
            let Some(name) = column.get("name").and_then(Value::as_str) else {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "columns entries require name",
                )
                .into());
            };
            let ty = match column.get("type").and_then(Value::as_str) {
                Some(name) => columnar_column_type_name(name)?,
                None => {
                    let Some(tag) = column.get("type_tag").and_then(Value::as_u64) else {
                        return Err(error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "columns entries require type or type_tag",
                        )
                        .into());
                    };
                    let tag = u8::try_from(tag).map_err(|_| {
                        error_response(
                            StatusCode::BAD_REQUEST,
                            Code::InvalidArgument,
                            "column type_tag is too large",
                        )
                    })?;
                    ColumnType::from_tag(tag)
                        .map_err(|err| loom_error_response(StatusCode::BAD_REQUEST, err))?
                }
            };
            Ok((name.to_string(), ty))
        })
        .collect()
}

fn columnar_column_type_name(name: &str) -> HostedHttpResult<ColumnType> {
    match name {
        "int" => Ok(ColumnType::Int),
        "float" => Ok(ColumnType::Float),
        "text" => Ok(ColumnType::Text),
        "bool" => Ok(ColumnType::Bool),
        "bytes" => Ok(ColumnType::Bytes),
        "i8" => Ok(ColumnType::I8),
        "i16" => Ok(ColumnType::I16),
        "i32" => Ok(ColumnType::I32),
        "i128" => Ok(ColumnType::I128),
        "u8" => Ok(ColumnType::U8),
        "u16" => Ok(ColumnType::U16),
        "u32" => Ok(ColumnType::U32),
        "u64" => Ok(ColumnType::U64),
        "u128" => Ok(ColumnType::U128),
        "f32" => Ok(ColumnType::F32),
        "decimal" => Ok(ColumnType::Decimal),
        "date" => Ok(ColumnType::Date),
        "time" => Ok(ColumnType::Time),
        "timestamp" => Ok(ColumnType::Timestamp),
        "interval" => Ok(ColumnType::Interval),
        "uuid" => Ok(ColumnType::Uuid),
        "inet" => Ok(ColumnType::Inet),
        "point" => Ok(ColumnType::Point),
        "list" => Ok(ColumnType::List),
        "map" => Ok(ColumnType::Map),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unknown column type",
        )
        .into()),
    }
}

fn columnar_row_field(
    value: &Value,
    columns: &[(String, ColumnType)],
) -> HostedHttpResult<Vec<DataValue>> {
    let Some(row) = value.get("row").and_then(Value::as_array) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "row must be an array",
        )
        .into());
    };
    if row.len() != columns.len() {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "row arity does not match columns",
        )
        .into());
    }
    row.iter()
        .zip(columns)
        .map(|(value, (_, ty))| columnar_value_for_type(value, *ty))
        .collect()
}

fn columnar_filter_field(
    value: &Value,
    columns: &[(String, ColumnType)],
) -> HostedHttpResult<Option<(String, CmpOp, DataValue)>> {
    let Some(filter) = value.get("filter") else {
        return Ok(None);
    };
    if filter.is_null() {
        return Ok(None);
    }
    let Some(filter) = filter.as_object() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "filter must be an object",
        )
        .into());
    };
    let Some(column) = filter.get("column").and_then(Value::as_str) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "filter.column must be a string",
        )
        .into());
    };
    let Some((_, ty)) = columns.iter().find(|(name, _)| name == column) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unknown filter column",
        )
        .into());
    };
    let op = match filter.get("op").and_then(Value::as_str) {
        Some("eq") | Some("==") => CmpOp::Eq,
        Some("ne") | Some("!=") => CmpOp::Ne,
        Some("lt") | Some("<") => CmpOp::Lt,
        Some("le") | Some("<=") => CmpOp::Le,
        Some("gt") | Some(">") => CmpOp::Gt,
        Some("ge") | Some(">=") => CmpOp::Ge,
        _ => {
            return Err(error_response(
                StatusCode::BAD_REQUEST,
                Code::InvalidArgument,
                "filter.op must be eq, ne, lt, le, gt, or ge",
            )
            .into());
        }
    };
    let Some(raw_value) = filter.get("value") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "filter.value is required",
        )
        .into());
    };
    Ok(Some((
        column.to_string(),
        op,
        columnar_value_for_type(raw_value, *ty)?,
    )))
}

fn columnar_aggregates_field(value: &Value) -> HostedHttpResult<Vec<ColumnarAggregate>> {
    let Some(values) = value.get("aggregates").and_then(Value::as_array) else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "aggregates must be an array",
        )
        .into());
    };
    values
        .iter()
        .map(|value| {
            let Some(value) = value.as_object() else {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "aggregate entries must be objects",
                )
                .into());
            };
            let op = match value.get("op").and_then(Value::as_str) {
                Some("count") => ColumnarAggregateOp::Count,
                Some("count_non_null") => ColumnarAggregateOp::CountNonNull,
                Some("min") => ColumnarAggregateOp::Min,
                Some("max") => ColumnarAggregateOp::Max,
                Some("sum") => ColumnarAggregateOp::Sum,
                _ => {
                    return Err(error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        "aggregate op must be count, count_non_null, min, max, or sum",
                    )
                    .into());
                }
            };
            let column = match value.get("column") {
                Some(Value::Null) | None => None,
                Some(Value::String(value)) if value.is_empty() => None,
                Some(Value::String(value)) => Some(value.clone()),
                Some(_) => {
                    return Err(error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        "aggregate column must be a string or null",
                    )
                    .into());
                }
            };
            Ok(ColumnarAggregate { op, column })
        })
        .collect()
}

fn columnar_value_for_type(value: &Value, ty: ColumnType) -> HostedHttpResult<DataValue> {
    if value.is_null() {
        return Ok(DataValue::Null);
    }
    match ty {
        ColumnType::Int => value
            .as_i64()
            .map(DataValue::Int)
            .ok_or_else(|| columnar_value_type_error("signed integer")),
        ColumnType::Float => value
            .as_f64()
            .map(DataValue::Float)
            .ok_or_else(|| columnar_value_type_error("number")),
        ColumnType::Text => value
            .as_str()
            .map(|value| DataValue::Text(value.to_string()))
            .ok_or_else(|| columnar_value_type_error("string")),
        ColumnType::Bool => value
            .as_bool()
            .map(DataValue::Bool)
            .ok_or_else(|| columnar_value_type_error("boolean")),
        ColumnType::Bytes => {
            let raw = value
                .get("bytes_hex")
                .and_then(Value::as_str)
                .or_else(|| value.as_str())
                .ok_or_else(|| columnar_value_type_error("hex string or bytes_hex object"))?;
            decode_hex(raw)
                .map(DataValue::Bytes)
                .map_err(|message| columnar_invalid_value(&message))
        }
        ColumnType::I8 => signed_narrow(value, "i8").and_then(|value| {
            i8::try_from(value)
                .map(DataValue::I8)
                .map_err(|_| columnar_value_type_error("i8"))
        }),
        ColumnType::I16 => signed_narrow(value, "i16").and_then(|value| {
            i16::try_from(value)
                .map(DataValue::I16)
                .map_err(|_| columnar_value_type_error("i16"))
        }),
        ColumnType::I32 | ColumnType::Date => signed_narrow(value, "i32").and_then(|value| {
            i32::try_from(value)
                .map(|value| {
                    if ty == ColumnType::Date {
                        DataValue::Date(value)
                    } else {
                        DataValue::I32(value)
                    }
                })
                .map_err(|_| columnar_value_type_error("i32"))
        }),
        ColumnType::I128 => signed_128(value).map(DataValue::I128),
        ColumnType::U8 => unsigned_narrow(value, "u8").and_then(|value| {
            u8::try_from(value)
                .map(DataValue::U8)
                .map_err(|_| columnar_value_type_error("u8"))
        }),
        ColumnType::U16 => unsigned_narrow(value, "u16").and_then(|value| {
            u16::try_from(value)
                .map(DataValue::U16)
                .map_err(|_| columnar_value_type_error("u16"))
        }),
        ColumnType::U32 => unsigned_narrow(value, "u32").and_then(|value| {
            u32::try_from(value)
                .map(DataValue::U32)
                .map_err(|_| columnar_value_type_error("u32"))
        }),
        ColumnType::U64 | ColumnType::Time => value
            .as_u64()
            .map(|value| {
                if ty == ColumnType::Time {
                    DataValue::Time(value)
                } else {
                    DataValue::U64(value)
                }
            })
            .ok_or_else(|| columnar_value_type_error("unsigned integer")),
        ColumnType::U128 | ColumnType::Uuid => unsigned_128(value).map(|value| {
            if ty == ColumnType::Uuid {
                DataValue::Uuid(value)
            } else {
                DataValue::U128(value)
            }
        }),
        ColumnType::F32 => value
            .as_f64()
            .map(|value| DataValue::F32(value as f32))
            .ok_or_else(|| columnar_value_type_error("number")),
        ColumnType::Decimal => {
            let Some(object) = value.as_object() else {
                return Err(columnar_value_type_error("decimal object"));
            };
            let mantissa = object
                .get("mantissa")
                .and_then(|value| value.as_str().and_then(|value| value.parse::<i128>().ok()))
                .or_else(|| {
                    object
                        .get("mantissa")
                        .and_then(Value::as_i64)
                        .map(i128::from)
                })
                .ok_or_else(|| columnar_value_type_error("decimal mantissa"))?;
            let scale = object
                .get("scale")
                .and_then(Value::as_u64)
                .and_then(|value| u32::try_from(value).ok())
                .ok_or_else(|| columnar_value_type_error("decimal scale"))?;
            Ok(DataValue::Decimal { mantissa, scale })
        }
        ColumnType::Timestamp => value
            .as_i64()
            .map(DataValue::Timestamp)
            .ok_or_else(|| columnar_value_type_error("signed integer")),
        ColumnType::Interval => {
            let Some(object) = value.as_object() else {
                return Err(columnar_value_type_error("interval object"));
            };
            let months = object
                .get("months")
                .and_then(Value::as_i64)
                .and_then(|value| i32::try_from(value).ok())
                .ok_or_else(|| columnar_value_type_error("interval months"))?;
            let micros = object
                .get("micros")
                .and_then(Value::as_i64)
                .ok_or_else(|| columnar_value_type_error("interval micros"))?;
            Ok(DataValue::Interval { months, micros })
        }
        ColumnType::Inet => value
            .as_str()
            .and_then(|value| value.parse::<std::net::IpAddr>().ok())
            .map(DataValue::Inet)
            .ok_or_else(|| columnar_value_type_error("IP address string")),
        ColumnType::Point => {
            let Some(object) = value.as_object() else {
                return Err(columnar_value_type_error("point object"));
            };
            let x = object
                .get("x")
                .and_then(Value::as_f64)
                .ok_or_else(|| columnar_value_type_error("point x"))?;
            let y = object
                .get("y")
                .and_then(Value::as_f64)
                .ok_or_else(|| columnar_value_type_error("point y"))?;
            Ok(DataValue::Point { x, y })
        }
        ColumnType::List => {
            let Some(values) = value.as_array() else {
                return Err(columnar_value_type_error("array"));
            };
            values
                .iter()
                .map(columnar_untyped_value)
                .collect::<HostedHttpResult<Vec<_>>>()
                .map(DataValue::List)
        }
        ColumnType::Map => {
            let Some(values) = value.as_object() else {
                return Err(columnar_value_type_error("object"));
            };
            values
                .iter()
                .map(|(key, value)| columnar_untyped_value(value).map(|value| (key.clone(), value)))
                .collect::<HostedHttpResult<BTreeMap<_, _>>>()
                .map(DataValue::Map)
        }
    }
}

fn columnar_untyped_value(value: &Value) -> HostedHttpResult<DataValue> {
    match value {
        Value::Null => Ok(DataValue::Null),
        Value::Bool(value) => Ok(DataValue::Bool(*value)),
        Value::Number(value) => {
            if let Some(value) = value.as_i64() {
                Ok(DataValue::Int(value))
            } else if let Some(value) = value.as_u64() {
                Ok(DataValue::U64(value))
            } else if let Some(value) = value.as_f64() {
                Ok(DataValue::Float(value))
            } else {
                Err(columnar_value_type_error("finite number"))
            }
        }
        Value::String(value) => Ok(DataValue::Text(value.clone())),
        Value::Array(values) => values
            .iter()
            .map(columnar_untyped_value)
            .collect::<HostedHttpResult<Vec<_>>>()
            .map(DataValue::List),
        Value::Object(values) => values
            .iter()
            .map(|(key, value)| columnar_untyped_value(value).map(|value| (key.clone(), value)))
            .collect::<HostedHttpResult<BTreeMap<_, _>>>()
            .map(DataValue::Map),
    }
}

fn signed_narrow(value: &Value, name: &str) -> HostedHttpResult<i64> {
    value
        .as_i64()
        .ok_or_else(|| columnar_value_type_error(name))
}

fn unsigned_narrow(value: &Value, name: &str) -> HostedHttpResult<u64> {
    value
        .as_u64()
        .ok_or_else(|| columnar_value_type_error(name))
}

fn signed_128(value: &Value) -> HostedHttpResult<i128> {
    value
        .as_i64()
        .map(i128::from)
        .or_else(|| value.as_str().and_then(|value| value.parse::<i128>().ok()))
        .ok_or_else(|| columnar_value_type_error("i128"))
}

fn unsigned_128(value: &Value) -> HostedHttpResult<u128> {
    value
        .as_u64()
        .map(u128::from)
        .or_else(|| value.as_str().and_then(|value| value.parse::<u128>().ok()))
        .ok_or_else(|| columnar_value_type_error("u128"))
}

fn columnar_invalid_value(message: &str) -> HostedHttpError {
    error_response(StatusCode::BAD_REQUEST, Code::InvalidArgument, message).into()
}

fn columnar_value_type_error(expected: &str) -> HostedHttpError {
    error_response(
        StatusCode::BAD_REQUEST,
        Code::InvalidArgument,
        &format!("columnar value must be {expected}"),
    )
    .into()
}

fn columnar_transfer_error_response(err: HostedError) -> Response {
    if err.code_name == Code::Unsupported.as_str() {
        hosted_error_response(StatusCode::NOT_IMPLEMENTED, err)
    } else {
        hosted_error_response(StatusCode::FORBIDDEN, err)
    }
}

fn columnar_columns_json(columns: Vec<(String, ColumnType)>) -> Value {
    Value::Array(
        columns
            .into_iter()
            .map(|(name, ty)| {
                json!({
                    "name": name,
                    "type": dataframe_column_type_name(ty),
                    "type_tag": ty.tag()
                })
            })
            .collect(),
    )
}

fn columnar_rows_json(rows: Vec<Vec<DataValue>>) -> Value {
    json!({
        "rows": rows
            .into_iter()
            .map(|row| Value::Array(row.into_iter().map(dataframe_value_json).collect()))
            .collect::<Vec<_>>()
    })
}

fn columnar_inspect_json(inspect: loom_core::ColumnarInspect) -> Value {
    json!({
        "columns": columnar_columns_json(inspect.columns),
        "rows": inspect.rows,
        "segment_count": inspect.segment_count,
        "target_segment_rows": inspect.target_segment_rows,
        "source_digest": inspect.source_digest.to_hex()
    })
}

fn qdrant_collection_matches(state: &DataRestState, collection: &str) -> HostedHttpResult<()> {
    if state.collection == collection {
        Ok(())
    } else {
        Err(error_response(
            StatusCode::NOT_FOUND,
            Code::NotFound,
            "collection is not served by this listener",
        )
        .into())
    }
}

fn qdrant_response(result: Value) -> Response {
    json_response(
        StatusCode::OK,
        &json!({ "result": result, "status": "ok", "time": 0.0 }).to_string(),
    )
}

fn qdrant_vector_specs(
    value: &Value,
) -> HostedHttpResult<Vec<(Option<String>, usize, loom_core::Metric)>> {
    let Some(vectors) = value.get("vectors") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vectors must be an object",
        )
        .into());
    };
    let object = vectors.as_object().ok_or_else(|| {
        error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vectors must be an object",
        )
    })?;
    if object.contains_key("size") {
        let (dim, metric) = qdrant_vector_spec(vectors)?;
        return Ok(vec![(None, dim, metric)]);
    }
    if object.is_empty() {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vectors must not be empty",
        )
        .into());
    }
    object
        .iter()
        .map(|(name, value)| {
            if name.is_empty() {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "named vector must not be empty",
                )
                .into());
            }
            let (dim, metric) = qdrant_vector_spec(value)?;
            Ok((Some(name.clone()), dim, metric))
        })
        .collect()
}

fn qdrant_vector_spec(value: &Value) -> HostedHttpResult<(usize, loom_core::Metric)> {
    let dim = required_usize(value, "size")?;
    let distance = value
        .get("distance")
        .and_then(Value::as_str)
        .unwrap_or("Cosine");
    Ok((dim, qdrant_metric(distance)?))
}

fn qdrant_metric(value: &str) -> HostedHttpResult<loom_core::Metric> {
    match value {
        "Cosine" | "cosine" => Ok(loom_core::Metric::Cosine),
        "Euclid" | "euclid" | "L2" | "l2" => Ok(loom_core::Metric::L2),
        "Dot" | "dot" => Ok(loom_core::Metric::Dot),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "distance must be Cosine, Euclid, or Dot",
        )
        .into()),
    }
}

fn qdrant_metric_json(metric: loom_core::Metric) -> &'static str {
    match metric {
        loom_core::Metric::Cosine => "Cosine",
        loom_core::Metric::L2 => "Euclid",
        loom_core::Metric::Dot => "Dot",
    }
}

fn qdrant_point_id(value: Option<&Value>) -> HostedHttpResult<String> {
    qdrant_required_id(value, "id")
}

fn qdrant_optional_id(value: Option<&Value>) -> HostedHttpResult<Option<String>> {
    match value {
        Some(Value::Null) | None => Ok(None),
        Some(value) => qdrant_required_id(Some(value), "offset").map(Some),
    }
}

fn qdrant_required_id(value: Option<&Value>, name: &str) -> HostedHttpResult<String> {
    match value {
        Some(Value::String(value)) if !value.is_empty() => Ok(value.clone()),
        Some(Value::Number(value)) => value
            .as_u64()
            .map(|value| value.to_string())
            .or_else(|| value.as_i64().map(|value| value.to_string()))
            .ok_or_else(|| {
                error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    &format!("{name} must be a string or integer"),
                )
                .into()
            }),
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must be a string or integer"),
        )
        .into()),
    }
}

fn qdrant_point_vectors(point: &Value) -> HostedHttpResult<Vec<(Option<String>, Vec<f32>)>> {
    let Some(value) = point.get("vector") else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vector must be an array or named-vector object",
        )
        .into());
    };
    qdrant_vectors_from_value(value)
}

fn qdrant_vectors_from_value(value: &Value) -> HostedHttpResult<Vec<(Option<String>, Vec<f32>)>> {
    if value.is_array() {
        return Ok(vec![(None, qdrant_f32_array(value, "vector")?)]);
    }
    let Some(object) = value.as_object() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "vector must be an array or named-vector object",
        )
        .into());
    };
    qdrant_reject_sparse_or_text_vector(object)?;
    if let Some(vector) = object.get("vector") {
        let name = object
            .get("name")
            .and_then(Value::as_str)
            .filter(|name| !name.is_empty())
            .map(str::to_string);
        if let Some(vector_object) = vector.as_object() {
            qdrant_reject_sparse_or_text_vector(vector_object)?;
        }
        return Ok(vec![(name, qdrant_f32_array(vector, "vector.vector")?)]);
    }
    if object.is_empty() {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "named vector object must not be empty",
        )
        .into());
    }
    object
        .iter()
        .map(|(name, vector)| {
            if name.is_empty() {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "named vector must not be empty",
                )
                .into());
            }
            if let Some(vector_object) = vector.as_object() {
                qdrant_reject_sparse_or_text_vector(vector_object)?;
            }
            Ok((Some(name.clone()), qdrant_f32_array(vector, name)?))
        })
        .collect()
}

fn qdrant_reject_sparse_or_text_vector(
    object: &serde_json::Map<String, Value>,
) -> HostedHttpResult<()> {
    if object.contains_key("indices")
        || object.contains_key("values")
        || object.contains_key("text")
        || object.contains_key("document")
        || object.contains_key("source_text")
    {
        Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "unsupported vector compatibility operation: qdrant sparse vectors or integrated embedding",
        )
        .into())
    } else {
        Ok(())
    }
}

fn qdrant_query_vector(value: &Value, name: &str) -> HostedHttpResult<(Option<String>, Vec<f32>)> {
    let Some(vector) = value
        .get(name)
        .or_else(|| (name == "query").then(|| value.get("vector")).flatten())
    else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must be an array or named-vector object"),
        )
        .into());
    };
    let mut vectors = qdrant_vectors_from_value(vector)?;
    if vectors.len() != 1 {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must contain exactly one vector"),
        )
        .into());
    }
    Ok(vectors.remove(0))
}

fn qdrant_f32_array(value: &Value, name: &str) -> HostedHttpResult<Vec<f32>> {
    let Some(values) = value.as_array() else {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            &format!("{name} must be an array"),
        )
        .into());
    };
    values
        .iter()
        .map(|value| {
            value
                .as_f64()
                .filter(|value| value.is_finite())
                .map(|value| value as f32)
                .ok_or_else(|| {
                    error_response(
                        StatusCode::BAD_REQUEST,
                        Code::InvalidArgument,
                        &format!("{name} entries must be finite numbers"),
                    )
                    .into()
                })
        })
        .collect()
}

fn qdrant_payload(value: Option<&Value>) -> HostedHttpResult<BTreeMap<String, loom_core::Value>> {
    match value {
        Some(Value::Object(values)) => values
            .iter()
            .map(|(key, value)| qdrant_payload_value(value).map(|value| (key.clone(), value)))
            .collect(),
        Some(Value::Null) | None => Ok(BTreeMap::new()),
        Some(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "payload must be an object",
        )
        .into()),
    }
}

fn qdrant_payload_value(value: &Value) -> HostedHttpResult<loom_core::Value> {
    match value {
        Value::Null => Ok(loom_core::Value::Null),
        Value::Bool(value) => Ok(loom_core::Value::Bool(*value)),
        Value::Number(value) => {
            if let Some(value) = value.as_i64() {
                Ok(loom_core::Value::Int(value))
            } else if let Some(value) = value.as_f64().filter(|value| value.is_finite()) {
                Ok(loom_core::Value::Float(value))
            } else {
                Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "payload number is outside supported range",
                )
                .into())
            }
        }
        Value::String(value) => Ok(loom_core::Value::Text(value.clone())),
        Value::Array(_) | Value::Object(_) => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "payload values must be null, bool, number, or string",
        )
        .into()),
    }
}

fn qdrant_delete_ids(value: &Value) -> HostedHttpResult<Vec<String>> {
    match value.get("points") {
        Some(Value::Array(values)) => values
            .iter()
            .map(|value| qdrant_required_id(Some(value), "points entry"))
            .collect(),
        Some(Value::Object(object)) => {
            let Some(Value::Array(values)) = object.get("ids") else {
                return Err(error_response(
                    StatusCode::BAD_REQUEST,
                    Code::InvalidArgument,
                    "points.ids must be an array",
                )
                .into());
            };
            values
                .iter()
                .map(|value| qdrant_required_id(Some(value), "points.ids entry"))
                .collect()
        }
        _ => Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "points must be an array or object with ids",
        )
        .into()),
    }
}

fn qdrant_filter(value: &Value) -> HostedHttpResult<loom_core::vector::MetaFilter> {
    crate::vector_compat::qdrant_filter_from_json(value.get("filter").unwrap_or(&Value::Null))
        .map_err(|err| HostedHttpError::from(loom_error_response(StatusCode::BAD_REQUEST, err)))
}

fn qdrant_limit(value: &Value) -> HostedHttpResult<usize> {
    let limit = optional_usize(value, "limit")?.unwrap_or(10);
    if limit == 0 {
        return Err(error_response(
            StatusCode::BAD_REQUEST,
            Code::InvalidArgument,
            "limit must be positive",
        )
        .into());
    }
    Ok(limit)
}

fn qdrant_with_payload(value: &Value) -> bool {
    match value.get("with_payload") {
        Some(Value::Bool(value)) => *value,
        Some(Value::Object(_)) | Some(Value::Array(_)) => true,
        _ => false,
    }
}

fn qdrant_with_payload_default_true(value: &Value) -> bool {
    match value.get("with_payload") {
        Some(Value::Bool(value)) => *value,
        Some(Value::Object(_)) | Some(Value::Array(_)) => true,
        _ => true,
    }
}

fn qdrant_with_vector(value: &Value) -> bool {
    match value.get("with_vector") {
        Some(Value::Bool(value)) => *value,
        Some(Value::Object(_)) | Some(Value::Array(_)) => true,
        _ => false,
    }
}

