    #[test]
    fn s3_rest_router_accepts_sigv4_app_credentials() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("s3-rest-router-sigv4");
            let _ns = init(&path, None);
            let credential_id = nid(42);
            let secret = [0x42u8; 32];
            let token = loom_core::app_credential_token(credential_id, &secret);
            let fs = FileStore::open(&path).unwrap();
            let mut identity = fs.identity_store().unwrap().unwrap();
            identity
                .create_app_credential(nid(1), credential_id, "s3", &secret, b"s3-sigv4-salt")
                .unwrap();
            fs.save_identity_store(&identity).unwrap();
            drop(fs);

            let router = s3_rest_router_with_policy(
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock),
                "main",
                None::<String>,
                16 * 1024 * 1024,
                HostedAuthPolicy::Passphrase,
            );
            let create = router
                .clone()
                .oneshot(s3_signed_request("PUT", "/photos", Vec::new(), &token))
                .await
                .unwrap();
            assert_eq!(create.status(), StatusCode::OK);
            let put = router
                .clone()
                .oneshot(s3_signed_request(
                    "PUT",
                    "/photos/signed.txt",
                    b"sigv4".to_vec(),
                    &token,
                ))
                .await
                .unwrap();
            assert_eq!(put.status(), StatusCode::OK);
            let get = router
                .clone()
                .oneshot(s3_signed_request(
                    "GET",
                    "/photos/signed.txt",
                    Vec::new(),
                    &token,
                ))
                .await
                .unwrap();
            assert_eq!(get.status(), StatusCode::OK);
            let body = to_bytes(get.into_body(), 16 * 1024 * 1024).await.unwrap();
            assert_eq!(body.as_ref(), b"sigv4");

            let rejected = router
                .clone()
                .oneshot(s3_signed_request(
                    "GET",
                    "/photos/signed.txt",
                    Vec::new(),
                    "loom_app_bad_bad",
                ))
                .await
                .unwrap();
            assert_eq!(rejected.status(), StatusCode::UNAUTHORIZED);
            let _ = std::fs::remove_file(path);
        });
    }

