    #[test]
    fn watch_rest_stream_emits_sse_frame_with_source_cursor() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("watch-stream-router");
            let (ns, c0, c1) = watch_history(&path);
            let kernel = HostedKernel::new(&path);
            let router = watch_rest_router_with_policy(
                kernel.clone(),
                ns,
                16 * 1024 * 1024,
                HostedAuthPolicy::OwnerOrPassphrase,
            );
            let auth = HostedAuth::passphrase(nid(1), "root-pass", "watch-stream-router");
            let sub = kernel
                .rest()
                .watch_subscribe(
                    &auth,
                    ns,
                    &HostedWatchSubscribeInput {
                        branch: Some("main".to_string()),
                        from: Some(c0.to_string()),
                        facet: Some("files".to_string()),
                        path_prefix: Some("b.".to_string()),
                        change_kinds: vec!["added".to_string()],
                    },
                )
                .unwrap();
            let uri = format!(
                "/watch:stream?cursor={}&max=10&interval_ms=10&debounce_ms=1&limit=1",
                percent_query(&sub.body.cursor)
            );

            let response = router
                .oneshot(
                    Request::builder()
                        .method("GET")
                        .uri(uri)
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();

            assert_eq!(response.status(), StatusCode::OK);
            let body = to_bytes(response.into_body(), 16 * 1024 * 1024)
                .await
                .unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("event: data-change"), "{body}");
            assert!(body.contains("\"source_cursor\":"), "{body}");
            assert!(body.contains(&c1.to_string()), "{body}");
            assert!(body.contains("\"key_hex\":\"622e747874\""), "{body}");
            let _ = std::fs::remove_file(path);
        });
    }

    #[test]
    fn carddav_router_serves_contact_resources() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("carddav-router");
            let ns = init(&path, None);
            let kernel =
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
            let router = carddav_router_with_policy(
                kernel.clone(),
                "main",
                16 * 1024 * 1024,
                HostedAuthPolicy::OwnerOrPassphrase,
            );
            let vcf =
                "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-1\r\nFN:Alice Example\r\nEND:VCARD\r\n";

            let mkcol = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("MKCOL")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(mkcol.status(), StatusCode::CREATED);

            let put = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(vcf))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(put.status(), StatusCode::CREATED);
            let etag = put
                .headers()
                .get("etag")
                .and_then(|value| value.to_str().ok())
                .and_then(|value| value.strip_prefix('"')?.strip_suffix('"'))
                .unwrap()
                .to_string();

            let get = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("GET")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(get.status(), StatusCode::OK);
            let get_content_type = get.headers().get(CONTENT_TYPE).cloned();
            assert_eq!(
                get.headers()
                    .get("etag")
                    .and_then(|value| value.to_str().ok()),
                Some(format!("\"{etag}\"").as_str())
            );
            let body = to_bytes(get.into_body(), 16 * 1024 * 1024).await.unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("FN:Alice Example"), "{body}");

            let head = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("HEAD")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(head.status(), StatusCode::OK);
            assert_eq!(head.headers().get(CONTENT_TYPE).cloned(), get_content_type);
            assert_eq!(
                head.headers()
                    .get("etag")
                    .and_then(|value| value.to_str().ok()),
                Some(format!("\"{etag}\"").as_str())
            );
            let head_body = to_bytes(head.into_body(), 16 * 1024 * 1024).await.unwrap();
            assert!(head_body.is_empty());

            let unsupported = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("POST")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(unsupported.status(), StatusCode::METHOD_NOT_ALLOWED);
            assert_eq!(
                unsupported
                    .headers()
                    .get("allow")
                    .and_then(|value| value.to_str().ok()),
                Some("OPTIONS, PROPFIND, PROPPATCH, MKCOL, REPORT, GET, HEAD, PUT, DELETE")
            );

            let propfind = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PROPFIND")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(propfind.status(), StatusCode::MULTI_STATUS);
            let body = to_bytes(propfind.into_body(), 16 * 1024 * 1024)
                .await
                .unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("/carddav/people/contact-1.vcf"), "{body}");
            assert!(body.contains("<CARD:addressbook/>"), "{body}");
            assert!(body.contains("<CARD:addressbook-multiget/>"), "{body}");
            assert!(body.contains("<CARD:addressbook-query/>"), "{body}");
            assert!(body.contains("<D:sync-collection/>"), "{body}");
            assert!(
                body.contains("<D:sync-token>loom-carddav-sync-v1:"),
                "{body}"
            );
            assert!(body.contains("<CS:getctag>loom-carddav-sync-v1:"), "{body}");
            assert!(body.contains("<CARD:supported-address-data>"), "{body}");
            assert!(!body.contains("application/vcard+xml"), "{body}");
            assert!(!body.contains("urn:ietf:params:xml:ns:vcard-4.0"), "{body}");
            assert!(
                body.contains(&format!("<D:getetag>\"{etag}\"</D:getetag>")),
                "{body}"
            );
            assert!(
                !body.contains("<D:getetag>\"contact-1\"</D:getetag>"),
                "{body}"
            );

            let delete = router
                .oneshot(
                    Request::builder()
                        .method("DELETE")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(delete.status(), StatusCode::NO_CONTENT);
            let entries = kernel
                .read(
                    &HostedAuth::passphrase(nid(1), "root-pass", "carddav-test"),
                    |loom| contacts::list_entries(loom, ns, "root", "people"),
                )
                .unwrap();
            assert!(entries.is_empty());
            let _ = std::fs::remove_file(path);
        });
    }

