            let bob = "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-2\r\nFN:Bob Example\r\nORG:Other Co\r\nEMAIL;TYPE=home:bob@example.net\r\nEND:VCARD\r\n";

