    #[test]
    fn carddav_router_serves_addressbook_multiget() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("carddav-addressbook-multiget");
            let _ns = init(&path, None);
            let router = carddav_router_with_policy(
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock),
                "main",
                16 * 1024 * 1024,
                HostedAuthPolicy::OwnerOrPassphrase,
            );
            let vcf =
                "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-1\r\nFN:Alice Example\r\nEND:VCARD\r\n";

            let mkcol = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("MKCOL")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(mkcol.status(), StatusCode::CREATED);

            let put = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(vcf))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(put.status(), StatusCode::CREATED);
            let etag = put
                .headers()
                .get("etag")
                .and_then(|value| value.to_str().ok())
                .and_then(|value| value.strip_prefix('"')?.strip_suffix('"'))
                .unwrap()
                .to_string();

            let report = router
                .oneshot(
                    Request::builder()
                        .method("REPORT")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(
                            r#"<?xml version="1.0" encoding="utf-8"?>
<CARD:addressbook-multiget xmlns:D="DAV:" xmlns:CARD="urn:ietf:params:xml:ns:carddav">
  <D:prop>
    <D:getetag/>
    <CARD:address-data/>
  </D:prop>
  <D:href>/carddav/people/contact-1.vcf</D:href>
  <D:href>/carddav/people/missing.vcf</D:href>
</CARD:addressbook-multiget>"#,
                        ))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(report.status(), StatusCode::MULTI_STATUS);
            let body = to_bytes(report.into_body(), 16 * 1024 * 1024)
                .await
                .unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("/carddav/people/contact-1.vcf"), "{body}");
            assert!(body.contains("/carddav/people/missing.vcf"), "{body}");
            assert!(body.contains("FN:Alice Example"), "{body}");
            assert!(
                body.contains(&format!("<D:getetag>\"{etag}\"</D:getetag>")),
                "{body}"
            );
            assert!(body.contains("HTTP/1.1 404 Not Found"), "{body}");
            let _ = std::fs::remove_file(path);
        });
    }

    #[test]
    fn carddav_router_serves_sync_collection() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("carddav-sync-collection");
            let _ns = init(&path, None);
            let router = carddav_router_with_policy(
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock),
                "main",
                16 * 1024 * 1024,
                HostedAuthPolicy::OwnerOrPassphrase,
            );
            let vcf =
                "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-1\r\nFN:Alice Example\r\nEND:VCARD\r\n";

            let mkcol = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("MKCOL")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(mkcol.status(), StatusCode::CREATED);

            let put = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(vcf))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(put.status(), StatusCode::CREATED);

            let initial = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("REPORT")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(
                            r#"<D:sync-collection xmlns:D="DAV:"><D:prop><D:getetag/></D:prop></D:sync-collection>"#,
                        ))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(initial.status(), StatusCode::MULTI_STATUS);
            let body = to_bytes(initial.into_body(), 16 * 1024 * 1024)
                .await
                .unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("/carddav/people/contact-1.vcf"), "{body}");
            assert!(body.contains("FN:Alice Example"), "{body}");
            let sync_token = body
                .split("<D:sync-token>")
                .nth(1)
                .and_then(|value| value.split("</D:sync-token>").next())
                .unwrap()
                .to_string();
            assert!(sync_token.starts_with("loom-carddav-sync-v1:"), "{body}");

            let noop = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("REPORT")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(format!(
                            r#"<D:sync-collection xmlns:D="DAV:"><D:sync-token>{}</D:sync-token><D:prop><D:getetag/></D:prop></D:sync-collection>"#,
                            sync_token
                        )))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(noop.status(), StatusCode::MULTI_STATUS);
            let body = to_bytes(noop.into_body(), 16 * 1024 * 1024).await.unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(!body.contains("/carddav/people/contact-1.vcf"), "{body}");
            assert!(body.contains(&sync_token), "{body}");

            let delete = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("DELETE")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(delete.status(), StatusCode::NO_CONTENT);

            let tombstone = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("REPORT")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(format!(
                            r#"<D:sync-collection xmlns:D="DAV:"><D:sync-token>{}</D:sync-token><D:prop><D:getetag/></D:prop></D:sync-collection>"#,
                            sync_token
                        )))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(tombstone.status(), StatusCode::MULTI_STATUS);
            let body = to_bytes(tombstone.into_body(), 16 * 1024 * 1024)
                .await
                .unwrap();
            let body = String::from_utf8(body.to_vec()).unwrap();
            assert!(body.contains("/carddav/people/contact-1.vcf"), "{body}");
            assert!(body.contains("HTTP/1.1 404 Not Found"), "{body}");

            let invalid = router
                .oneshot(
                    Request::builder()
                        .method("REPORT")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(
                            r#"<D:sync-collection xmlns:D="DAV:"><D:sync-token>loom-carddav-sync-v1:not-a-digest</D:sync-token></D:sync-collection>"#,
                        ))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(invalid.status(), StatusCode::CONFLICT);
            let _ = std::fs::remove_file(path);
        });
    }

    #[test]
    fn carddav_router_enforces_write_preconditions() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("carddav-write-preconditions");
            let _ns = init(&path, None);
            let router = carddav_router_with_policy(
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock),
                "main",
                16 * 1024 * 1024,
                HostedAuthPolicy::OwnerOrPassphrase,
            );
            let initial =
                "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-1\r\nFN:Alice Example\r\nEND:VCARD\r\n";
            let changed =
                "BEGIN:VCARD\r\nVERSION:4.0\r\nUID:contact-1\r\nFN:Alice Updated\r\nEND:VCARD\r\n";

            let mkcol = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("MKCOL")
                        .uri("/carddav/people")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(mkcol.status(), StatusCode::CREATED);

            let put = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .body(Body::from(initial))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(put.status(), StatusCode::CREATED);
            let etag = put
                .headers()
                .get("etag")
                .and_then(|value| value.to_str().ok())
                .unwrap()
                .to_string();

            let create_only = router
                .clone()
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .header("if-none-match", "*")
                        .body(Body::from(changed))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(create_only.status(), StatusCode::PRECONDITION_FAILED);

            let delete = router
                .oneshot(
                    Request::builder()
                        .method("DELETE")
                        .uri("/carddav/people/contact-1.vcf")
                        .header("x-loom-principal", nid(1).to_string())
                        .header("x-loom-passphrase", "root-pass")
                        .header("if-match", etag)
                        .body(Body::empty())
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(delete.status(), StatusCode::NO_CONTENT);
            let _ = std::fs::remove_file(path);
        });
    }

    #[test]
    fn cas_rest_http_round_trips() {
        let path = temp_path("cas-http");
        let fs = FileStore::create_with_profile(&path, Algo::Blake3).unwrap();
        drop(fs);
        let mut loom = open_loom_unlocked(&path, None).unwrap();
        let ns = loom
            .registry_mut()
            .create(
                FacetKind::Cas,
                Some("main"),
                WorkspaceId::v4_from_bytes([8; 16]),
            )
            .unwrap();
        save_loom(&mut loom).unwrap();
        drop(loom);

        let runtime = tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .unwrap();
        let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel::<()>();
        let listener = runtime
            .block_on(tokio::net::TcpListener::bind("127.0.0.1:0"))
            .unwrap();
        let addr = listener.local_addr().unwrap();
        let kernel = HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
        let join = runtime.spawn(serve_cas_rest(listener, kernel, ns, async move {
            let _ = shutdown_rx.await;
        }));

        let put = http_request(
            addr,
            "PUT /cas HTTP/1.1\r\nHost: localhost\r\nConnection: close\r\nContent-Length: 5\r\n\r\nalpha",
        );
        assert!(
            put.starts_with("HTTP/1.1 201 Created"),
            "unexpected PUT response: {put}"
        );
        let digest = put
            .split("\"digest\":\"")
            .nth(1)
            .and_then(|rest| rest.split('"').next())
            .unwrap();
        let get = http_request(
            addr,
            &format!("GET /cas/{digest} HTTP/1.1\r\nHost: localhost\r\nConnection: close\r\n\r\n"),
        );
        assert!(get.starts_with("HTTP/1.1 200 OK"));
        assert!(get.ends_with("alpha"));
        let list = http_request(
            addr,
            "GET /cas HTTP/1.1\r\nHost: localhost\r\nConnection: close\r\n\r\n",
        );
        assert!(list.contains(digest));

        let _ = shutdown_tx.send(());
        runtime.block_on(join).unwrap().unwrap();
        assert_eq!(
            open_loom_unlocked(&path, None)
                .unwrap()
                .registry()
                .open(&WsSelector::Name("main".into()))
                .unwrap(),
            ns
        );
        std::fs::remove_file(path).unwrap();
    }

    #[test]
    fn hosted_http_limits_close_slow_or_expired_connections() {
        let path = temp_path("cas-http-limits");
        let fs = FileStore::create_with_profile(&path, Algo::Blake3).unwrap();
        drop(fs);
        let mut loom = open_loom_unlocked(&path, None).unwrap();
        let ns = loom
            .registry_mut()
            .create(
                FacetKind::Cas,
                Some("main"),
                WorkspaceId::v4_from_bytes([18; 16]),
            )
            .unwrap();
        save_loom(&mut loom).unwrap();
        drop(loom);

        let runtime = tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .unwrap();
        let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel::<()>();
        let listener = runtime
            .block_on(tokio::net::TcpListener::bind("127.0.0.1:0"))
            .unwrap();
        let addr = listener.local_addr().unwrap();
        let kernel = HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
        let limits = HostedHttpLimits::new(16 * 1024 * 1024, 100, 250).unwrap();
        let join = runtime.spawn(serve_cas_rest_with_limits(
            listener,
            kernel,
            ns,
            limits,
            HostedAuthPolicy::OwnerOrPassphrase,
            async move {
                let _ = shutdown_rx.await;
            },
        ));

        let slow = partial_http_request(addr, "GET /cas HTTP/1.1\r\nHost: localhost\r\n");
        assert!(slow.is_empty(), "{slow}");

        let expired = delayed_http_request(
            addr,
            std::time::Duration::from_millis(350),
            "GET /cas HTTP/1.1\r\nHost: localhost\r\nConnection: close\r\n\r\n",
        );
        assert!(!expired.starts_with("HTTP/1.1 200 OK"), "{expired}");

        let _ = shutdown_tx.send(());
        runtime.block_on(join).unwrap().unwrap();
        std::fs::remove_file(path).unwrap();
    }

    #[test]
    fn hosted_auth_policy_requires_passphrase_headers() {
        let missing = HeaderMap::new();
        let err = hosted_auth(&missing, HostedAuthPolicy::Passphrase)
            .unwrap_err()
            .into_response();
        assert_eq!(err.status(), StatusCode::UNAUTHORIZED);
        assert!(hosted_auth(&missing, HostedAuthPolicy::OwnerOrPassphrase).is_ok());

        let root = nid(1);
        let mut headers = HeaderMap::new();
        headers.insert("x-loom-principal", root.to_string().parse().unwrap());
        headers.insert("x-loom-passphrase", "root-pass".parse().unwrap());
        headers.insert("x-loom-session", "passphrase-test".parse().unwrap());
        let auth = match hosted_auth(&headers, HostedAuthPolicy::Passphrase) {
            Ok(auth) => auth,
            Err(_) => panic!("passphrase headers were rejected"),
        };
        assert_eq!(auth.principal, Some(root));
        assert_eq!(auth.passphrase.as_deref(), Some("root-pass"));
        assert_eq!(auth.session_id, "passphrase-test");

        let mut api_key_headers = HeaderMap::new();
        api_key_headers.insert("x-pinecone-api-key", "loom_app_token".parse().unwrap());
        api_key_headers.insert("x-loom-session", "api-key-test".parse().unwrap());
        let auth = match hosted_auth(&api_key_headers, HostedAuthPolicy::Passphrase) {
            Ok(auth) => auth,
            Err(_) => panic!("API-key header was rejected"),
        };
        assert_eq!(auth.app_credential.as_deref(), Some("loom_app_token"));
        assert_eq!(auth.session_id, "api-key-test");

        for (kind, parsed) in [
            ("public-key", ExternalCredentialKind::PublicKey),
            ("mtls-certificate", ExternalCredentialKind::MtlsCertificate),
            ("passkey", ExternalCredentialKind::Passkey),
            ("oidc-subject", ExternalCredentialKind::OidcSubject),
            ("saml-subject", ExternalCredentialKind::SamlSubject),
        ] {
            let mut external_headers = HeaderMap::new();
            external_headers.insert("x-loom-external-kind", kind.parse().unwrap());
            external_headers.insert("x-loom-external-issuer", "issuer".parse().unwrap());
            external_headers.insert("x-loom-external-subject", "subject".parse().unwrap());
            external_headers.insert(
                "x-loom-external-material-digest",
                "sha256:metadata".parse().unwrap(),
            );
            external_headers.insert("x-loom-session", "external-test".parse().unwrap());
            let auth = match hosted_auth(&external_headers, HostedAuthPolicy::Passphrase) {
                Ok(auth) => auth,
                Err(_) => panic!("verified external assertion headers were rejected"),
            };
            let credential = auth
                .verified_external
                .expect("verified external assertion was not captured");
            assert_eq!(credential.kind, parsed);
            assert_eq!(credential.issuer, "issuer");
            assert_eq!(credential.subject, "subject");
            assert_eq!(
                credential.material_digest.as_deref(),
                Some("sha256:metadata")
            );
            assert_eq!(auth.session_id, "external-test");
        }

        let mut mixed_headers = api_key_headers.clone();
        mixed_headers.insert("x-api-key", "loom_app_other".parse().unwrap());
        let err = hosted_auth(&mixed_headers, HostedAuthPolicy::Passphrase)
            .unwrap_err()
            .into_response();
        assert_eq!(err.status(), StatusCode::BAD_REQUEST);

        let mut mixed_external = api_key_headers.clone();
        mixed_external.insert("x-loom-external-kind", "oidc-subject".parse().unwrap());
        mixed_external.insert("x-loom-external-issuer", "issuer".parse().unwrap());
        mixed_external.insert("x-loom-external-subject", "subject".parse().unwrap());
        let err = hosted_auth(&mixed_external, HostedAuthPolicy::Passphrase)
            .unwrap_err()
            .into_response();
        assert_eq!(err.status(), StatusCode::BAD_REQUEST);

        let mut direct_proof = HeaderMap::new();
        direct_proof.insert(
            "x-loom-external-proof-kind",
            "mtls-certificate".parse().unwrap(),
        );
        direct_proof.insert("x-loom-external-proof", "{}".parse().unwrap());
        let err = hosted_auth(&direct_proof, HostedAuthPolicy::Passphrase)
            .unwrap_err()
            .into_response();
        assert_eq!(err.status(), StatusCode::NOT_IMPLEMENTED);

        let mut mixed_direct = direct_proof.clone();
        mixed_direct.insert("x-loom-external-kind", "oidc-subject".parse().unwrap());
        mixed_direct.insert("x-loom-external-issuer", "issuer".parse().unwrap());
        mixed_direct.insert("x-loom-external-subject", "subject".parse().unwrap());
        let err = hosted_auth(&mixed_direct, HostedAuthPolicy::Passphrase)
            .unwrap_err()
            .into_response();
        assert_eq!(err.status(), StatusCode::BAD_REQUEST);
    }

    #[cfg(feature = "external-auth")]
    #[test]
    fn cas_router_uses_trusted_peer_certificate_for_mtls_direct_proof() {
        let runtime = tokio::runtime::Runtime::new().unwrap();
        runtime.block_on(async {
            let path = temp_path("cas-mtls-peer-proof");
            let ns = init(&path, None);
            let rcgen::CertifiedKey { cert, .. } =
                rcgen::generate_simple_self_signed(vec!["client.example".to_string()]).unwrap();
            let leaf = cert.der().as_ref().to_vec();
            let material_digest = loom_core::Digest::hash(Algo::Sha256, &leaf).to_string();
            let fs = FileStore::open(&path).unwrap();
            let mut identity = fs.identity_store().unwrap().unwrap();
            identity
                .create_external_credential(
                    nid(1),
                    loom_core::ExternalCredentialSpec {
                        id: nid(31),
                        kind: ExternalCredentialKind::MtlsCertificate,
                        label: "client-cert".to_string(),
                        issuer: "loom-ca".to_string(),
                        subject: "client.example".to_string(),
                        material_digest: Some(material_digest.clone()),
                    },
                )
                .unwrap();
            fs.save_identity_store(&identity).unwrap();
            drop(fs);

            let kernel =
                HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
            let router = cas_rest_router_with_policy(
                kernel,
                ns,
                16 * 1024 * 1024,
                HostedAuthPolicy::Passphrase,
            );
            let proof = serde_json::json!({
                "issuer": "loom-ca",
                "subject": "client.example",
                "material_digest": material_digest
            })
            .to_string();
            let response = router
                .oneshot(
                    Request::builder()
                        .method("PUT")
                        .uri("/cas")
                        .header("x-loom-external-proof-kind", "mtls-certificate")
                        .header("x-loom-external-proof", proof)
                        .extension(HostedPeerCertificate::from_leaf_der(leaf))
                        .body(Body::from("mtls"))
                        .unwrap(),
                )
                .await
                .unwrap();
            assert_eq!(response.status(), StatusCode::CREATED);
            std::fs::remove_file(path).unwrap();
        });
    }

