    #[test]
    fn vcs_rest_http_round_trips_history() {
        let path = temp_path("vcs-rest-http");
        let ns = init(&path, None);
        let auth = HostedAuth::passphrase(nid(1), "root-pass", "setup");
        HostedKernel::new(&path)
            .write(&auth, |loom| {
                loom.create_directory(ns, "docs", true)?;
                loom.write_file(ns, "docs/a.txt", b"alpha", 0o100644)
            })
            .unwrap();

        let runtime = tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .unwrap();
        let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel::<()>();
        let listener = runtime
            .block_on(tokio::net::TcpListener::bind("127.0.0.1:0"))
            .unwrap();
        let addr = listener.local_addr().unwrap();
        let kernel = HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
        let join = runtime.spawn(serve_vcs_rest(listener, kernel, ns, async move {
            let _ = shutdown_rx.await;
        }));

        let commit_one = http_request(
            addr,
            &json_http_request_root(
                "POST",
                "/commits",
                "{\"message\":\"one\",\"author\":\"root\"}",
            ),
        );
        assert!(
            commit_one.starts_with("HTTP/1.1 201 Created"),
            "{commit_one}"
        );
        let first = commit_one
            .split("\"commit\":\"")
            .nth(1)
            .and_then(|rest| rest.split('"').next())
            .unwrap()
            .to_string();
        HostedKernel::new(&path)
            .write(&auth, |loom| {
                loom.write_file(ns, "docs/a.txt", b"bravo", 0o100644)
            })
            .unwrap();
        let commit_two = http_request(
            addr,
            &json_http_request_root(
                "POST",
                "/commits",
                "{\"message\":\"two\",\"author\":\"root\"}",
            ),
        );
        assert!(
            commit_two.starts_with("HTTP/1.1 201 Created"),
            "{commit_two}"
        );
        let second = commit_two
            .split("\"commit\":\"")
            .nth(1)
            .and_then(|rest| rest.split('"').next())
            .unwrap()
            .to_string();
        let log = http_request(addr, &json_http_request_root("GET", "/commits?limit=2", ""));
        assert!(log.contains(&first), "{log}");
        assert!(log.contains(&second), "{log}");
        let branch = http_request(
            addr,
            &json_http_request_root("PUT", "/refs/branch/feature", ""),
        );
        assert!(branch.starts_with("HTTP/1.1 204 No Content"), "{branch}");
        let checkout = http_request(
            addr,
            &json_http_request_root("POST", "/vcs:checkout", "{\"target\":\"feature\"}"),
        );
        assert!(
            checkout.starts_with("HTTP/1.1 204 No Content"),
            "{checkout}"
        );
        let diff_body = format!("{{\"from\":\"{first}\",\"to\":\"{second}\",\"format\":\"hex\"}}");
        let diff = http_request(
            addr,
            &json_http_request_root("POST", "/vcs:diff", &diff_body),
        );
        assert!(diff.contains("\"diff_cbor_hex\":\""), "{diff}");

        let _ = shutdown_tx.send(());
        runtime.block_on(join).unwrap().unwrap();
        std::fs::remove_file(path).unwrap();
    }

