    #[test]
    fn sql_rest_http_exec_and_query_round_trip() {
        let path = temp_path("sql-rest-http");
        let _ = std::fs::remove_file(&path);
        let fs = FileStore::create_with_profile(&path, Algo::Blake3).unwrap();
        drop(fs);
        let mut loom = open_loom_unlocked(&path, None).unwrap();
        loom.registry_mut()
            .create(
                FacetKind::Sql,
                Some("main"),
                WorkspaceId::v4_from_bytes([33; 16]),
            )
            .unwrap();
        save_loom(&mut loom).unwrap();
        drop(loom);

        let runtime = tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .unwrap();
        let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel::<()>();
        let listener = runtime
            .block_on(tokio::net::TcpListener::bind("127.0.0.1:0"))
            .unwrap();
        let addr = listener.local_addr().unwrap();
        let kernel = HostedKernel::new(&path).with_write_guard(HostedWriteGuard::DirectFileLock);
        let join = runtime.spawn(serve_sql_rest(listener, kernel, "main", "db", async move {
            let _ = shutdown_rx.await;
        }));

        let create_body = "{\"sql\":\"CREATE TABLE t (id INTEGER PRIMARY KEY, v TEXT); INSERT INTO t VALUES (1, 'a')\"}";
        let create_bytes =
            http_request_bytes(addr, &json_http_request("POST", "/sql:exec", create_body));
        let create = String::from_utf8_lossy(&create_bytes);
        assert!(create.starts_with("HTTP/1.1 200 OK"), "{create}");
        assert!(
            create.contains("content-type: application/cbor"),
            "{create}"
        );

        let query_body = "{\"sql\":\"SELECT id, v FROM t\"}";
        let query_bytes =
            http_request_bytes(addr, &json_http_request("POST", "/sql:query", query_body));
        let query = String::from_utf8_lossy(&query_bytes);
        assert!(query.starts_with("HTTP/1.1 200 OK"), "{query}");
        assert!(query.contains("content-type: application/cbor"), "{query}");

        let denied_body = "{\"sql\":\"INSERT INTO t VALUES (2, 'b')\"}";
        let denied = http_request(addr, &json_http_request("POST", "/sql:query", denied_body));
        assert!(denied.starts_with("HTTP/1.1 403 Forbidden"), "{denied}");
        assert!(
            denied.contains("\"code\":\"PERMISSION_DENIED\""),
            "{denied}"
        );

        let _ = shutdown_tx.send(());
        runtime.block_on(join).unwrap().unwrap();
        std::fs::remove_file(path).unwrap();
    }

