            let mut structure_root = response_json(&structure)
                .pointer("/structure/profile_root")
                .and_then(serde_json::Value::as_str)
                .unwrap()
                .to_string();
            let node_a = http_request_complete(
                addr,
                &json_http_request_root(
                    "POST",
                    "/structures:add-node",
                    &format!(
                        "{{\"structure_id\":\"plan\",\"node_id\":\"n1\",\"kind\":\"page\",\"label\":\"Roadmap\",\"entity_ref\":\"page:roadmap\",\"expected_root\":\"{structure_root}\"}}"
                    ),
                ),
            );
            assert!(node_a.contains("\"node_id\":\"n1\""), "{node_a}");
            structure_root = response_json(&node_a)
                .get("profile_root")
